const document: HandbookDocumentContent = {
  navHtml: "<div class=\"nav-brand\">PRACTICE · BUILD RELEASE</div>\n  <div class=\"nav-title\">실무 빌드 · 설정 DB 배포 로그</div>\n  <a href=\"#bundle-index\"><span class=\"code\">INDEX</span>통합 문서</a>\n  <a href=\"#doc-gradle\"><span class=\"code\">DOC</span>Gradle 의존성·빌드</a>\n  <a href=\"#doc-packages\"><span class=\"code\">DOC</span>패키지·버전 매니저</a>\n  <a href=\"#doc-config\"><span class=\"code\">DOC</span>환경변수·설정</a>\n  <a href=\"#doc-dbseed\"><span class=\"code\">DOC</span>DB 스키마·시딩</a>\n  <a href=\"#doc-cicd\"><span class=\"code\">DOC</span>CI/CD 배포</a>\n  <a href=\"#doc-logs\"><span class=\"code\">DOC</span>로그·커스텀 명령</a>\n  <a href=\"#doc-gradle\"><span class=\"code\">SRC</span>Gradle 의존성·빌드</a>\n<a href=\"#gradle-ch1\"><span class=\"code\">GRADLE-01</span>Gradle이 하는 일·구조</a>\n  <a href=\"#gradle-ch2\"><span class=\"code\">GRADLE-02</span>의존성 추가</a>\n  <a href=\"#gradle-ch3\"><span class=\"code\">GRADLE-03</span>의존성 스코프</a>\n  <a href=\"#gradle-ch4\"><span class=\"code\">GRADLE-04</span>버전 관리</a>\n  <a href=\"#gradle-ch5\"><span class=\"code\">GRADLE-05</span>플러그인</a>\n  <a href=\"#gradle-ch6\"><span class=\"code\">GRADLE-06</span>의존성 확인·트러블슈팅</a>\n  <a href=\"#gradle-ch7\"><span class=\"code\">GRADLE-07</span>자주 쓰는 task</a>\n  <a href=\"#gradle-ch8\"><span class=\"code\">GRADLE-08</span>멀티모듈 기초</a>\n  <a href=\"#gradle-ch9\"><span class=\"code\">GRADLE-09</span>치트시트</a>\n  <a href=\"#doc-packages\"><span class=\"code\">SRC</span>패키지·버전 매니저</a>\n<a href=\"#packages-ch1\"><span class=\"code\">PKG-01</span>두 범주를 구분하라</a>\n  <a href=\"#packages-ch2\"><span class=\"code\">PKG-02</span>npm 기본</a>\n  <a href=\"#packages-ch3\"><span class=\"code\">PKG-03</span>pnpm</a>\n  <a href=\"#packages-ch4\"><span class=\"code\">PKG-04</span>npm vs pnpm vs yarn</a>\n  <a href=\"#packages-ch5\"><span class=\"code\">PKG-05</span>lockfile과 재현성</a>\n  <a href=\"#packages-ch6\"><span class=\"code\">PKG-06</span>워크스페이스(모노레포)</a>\n  <a href=\"#packages-ch7\"><span class=\"code\">PKG-07</span>nvm — Node 버전 매니저</a>\n  <a href=\"#packages-ch8\"><span class=\"code\">PKG-08</span>mise — 폴리글랏 매니저</a>\n  <a href=\"#packages-ch9\"><span class=\"code\">PKG-09</span>치트시트</a>\n  <a href=\"#doc-config\"><span class=\"code\">SRC</span>환경변수·설정</a>\n<a href=\"#config-ch1\"><span class=\"code\">CONFIG-01</span>왜 설정을 외부화하나</a>\n  <a href=\"#config-ch2\"><span class=\"code\">CONFIG-02</span>yml vs properties</a>\n  <a href=\"#config-ch3\"><span class=\"code\">CONFIG-03</span>프로파일로 환경 분리</a>\n  <a href=\"#config-ch4\"><span class=\"code\">CONFIG-04</span>환경변수 주입</a>\n  <a href=\"#config-ch5\"><span class=\"code\">CONFIG-05</span>설정 우선순위</a>\n  <a href=\"#config-ch6\"><span class=\"code\">CONFIG-06</span>코드에서 읽기</a>\n  <a href=\"#config-ch7\"><span class=\"code\">CONFIG-07</span>시크릿 분리</a>\n  <a href=\"#config-ch8\"><span class=\"code\">CONFIG-08</span>로컬 개발 설정</a>\n  <a href=\"#config-ch9\"><span class=\"code\">CONFIG-09</span>치트시트</a>\n  <a href=\"#doc-dbseed\"><span class=\"code\">SRC</span>DB 스키마·시딩</a>\n<a href=\"#dbseed-ch1\"><span class=\"code\">SEED-01</span>스키마는 누가 관리하나</a>\n  <a href=\"#dbseed-ch2\"><span class=\"code\">SEED-02</span>마이그레이션 도구 — Flyway</a>\n  <a href=\"#dbseed-ch3\"><span class=\"code\">SEED-03</span>마이그레이션 작성 패턴</a>\n  <a href=\"#dbseed-ch4\"><span class=\"code\">SEED-04</span>로컬 시딩 방법 비교</a>\n  <a href=\"#dbseed-ch5\"><span class=\"code\">SEED-05</span>멱등 시더 작성</a>\n  <a href=\"#dbseed-ch6\"><span class=\"code\">SEED-06</span>로컬 리셋 워크플로우</a>\n  <a href=\"#dbseed-ch7\"><span class=\"code\">SEED-07</span>테스트 데이터</a>\n  <a href=\"#dbseed-ch8\"><span class=\"code\">SEED-08</span>치트시트</a>\n  <a href=\"#doc-cicd\"><span class=\"code\">SRC</span>CI/CD 배포</a>\n<a href=\"#cicd-ch1\"><span class=\"code\">CICD-01</span>CI/CD가 하는 일</a>\n  <a href=\"#cicd-ch2\"><span class=\"code\">CICD-02</span>GitHub Actions 기본</a>\n  <a href=\"#cicd-ch3\"><span class=\"code\">CICD-03</span>빌드·테스트 워크플로우</a>\n  <a href=\"#cicd-ch4\"><span class=\"code\">CICD-04</span>이미지 빌드·푸시</a>\n  <a href=\"#cicd-ch5\"><span class=\"code\">CICD-05</span>시크릿·환경</a>\n  <a href=\"#cicd-ch6\"><span class=\"code\">CICD-06</span>배포 트리거·전략</a>\n  <a href=\"#cicd-ch7\"><span class=\"code\">CICD-07</span>파이프라인 베스트</a>\n  <a href=\"#cicd-ch8\"><span class=\"code\">CICD-08</span>치트시트</a>\n  <a href=\"#doc-logs\"><span class=\"code\">SRC</span>로그·커스텀 명령</a>\n<a href=\"#logs-ch1\"><span class=\"code\">LOGTL-01</span>로그를 어디서 보나</a>\n  <a href=\"#logs-ch2\"><span class=\"code\">LOGTL-02</span>로그 필터링</a>\n  <a href=\"#logs-ch3\"><span class=\"code\">LOGTL-03</span>구조화(JSON) 로그</a>\n  <a href=\"#logs-ch4\"><span class=\"code\">LOGTL-04</span>런타임 로그 레벨 변경</a>\n  <a href=\"#logs-ch5\"><span class=\"code\">LOGTL-05</span>셸 alias·함수</a>\n  <a href=\"#logs-ch6\"><span class=\"code\">LOGTL-06</span>스크립트화</a>\n  <a href=\"#logs-ch7\"><span class=\"code\">LOGTL-07</span>프로젝트 커스텀 명령</a>\n  <a href=\"#logs-ch8\"><span class=\"code\">LOGTL-08</span>치트시트</a>",
  mainHtml: "<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : PRACTICE-BUILD-RELEASE</span>\n    <span>SCOPE : BUILD · CONFIG · DB · CI/CD · LOGS</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>실무 빌드와 릴리스 운영</h1>\n  <p class=\"hero-sub\">Gradle, 패키지·버전 매니저, 환경변수·설정, DB 스키마·시딩, CI/CD 배포, 로그·커스텀 명령을 통합했습니다.</p>\n  <div class=\"hero-meta\">CURATED HANDBOOK PATH · SOURCES : 6 DOCUMENTS · UPDATED 2026-06</div>\n</header>\n\n<section id=\"bundle-index\">\n<div class=\"ch-head\"><span class=\"ch-code\">INDEX</span><h2>통합 문서</h2></div>\n<p class=\"lede\">아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다.</p>\n<ul><li>Gradle 의존성·빌드</li><li>패키지·버전 매니저</li><li>환경변수·설정</li><li>DB 스키마·시딩</li><li>CI/CD 배포</li><li>로그·커스텀 명령</li></ul>\n</section>\n\n<section id=\"doc-gradle\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>Gradle 의존성·빌드</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : GRADLE-GUIDE-V1</span>\n    <span>SCOPE : DEPENDENCY · BUILD</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>Gradle 의존성·빌드<br>실무 가이드</h1>\n  <p class=\"hero-sub\">라이브러리를 어떻게 추가·고정·갱신하는가 — <strong>npm/package.json 하던 감각을 Gradle로 옮기는</strong> 실무 가이드. 개념 설명보다 \"이걸 실제로 어떻게 치나\"에 답합니다. Gradle 8.x · Spring Boot 3.x · Java 기준.</p>\n  <div class=\"hero-meta\">NOTE : 빌드 스크립트는 Groovy DSL(<code>build.gradle</code>) 기준 표기 — Kotlin DSL(<code>.gradle.kts</code>)은 문법이 조금 다름<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"gradle-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">GRADLE-01</span><h2>Gradle이 하는 일·구조</h2></div>\n<p class=\"lede\">Gradle은 JVM 세계의 빌드 도구입니다 — npm이 의존성 설치·스크립트 실행을 맡듯, Gradle은 <em>의존성 해석 + 컴파일 + 테스트 + 패키징</em>을 한 번에 책임집니다. 프론트엔드 감각으로 매핑부터 잡으면 빠릅니다.</p>\n<table>\n<tr><th>npm 세계</th><th>Gradle 세계</th><th>역할</th></tr>\n<tr><td><code>package.json</code></td><td><code>build.gradle</code></td><td>의존성·플러그인·빌드 설정 선언</td></tr>\n<tr><td>workspaces 루트 설정</td><td><code>settings.gradle</code></td><td>프로젝트 이름·포함할 모듈 정의</td></tr>\n<tr><td><code>node_modules</code></td><td><code>~/.gradle/caches</code></td><td>받은 라이브러리 저장(프로젝트별 아님, 전역 캐시)</td></tr>\n<tr><td><code>package-lock.json</code></td><td>resolved 버전(+version catalog)</td><td>실제 해석된 버전 고정</td></tr>\n<tr><td><code>npx</code> / <code>npm run</code></td><td><code>./gradlew &lt;task&gt;</code></td><td>빌드·실행 task 호출</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">프로젝트 루트 구조</span>\nmy-app/<br>\n├─ <span class=\"seg\">build.gradle</span> <span class=\"dim\">← 의존성·플러그인 (≈ package.json)</span><br>\n├─ <span class=\"seg\">settings.gradle</span> <span class=\"dim\">← 프로젝트/모듈 정의</span><br>\n├─ <span class=\"seg2\">gradlew</span> · <span class=\"seg2\">gradlew.bat</span> <span class=\"dim\">← wrapper 실행 스크립트</span><br>\n├─ gradle/wrapper/<span class=\"dim\">gradle-wrapper.properties ← 고정된 Gradle 버전</span><br>\n└─ src/main/java · src/test/java <span class=\"dim\">← 소스</span>\n</div>\n<h3><span class=\"h3-tag\">1.1</span>gradlew(wrapper)를 왜 쓰나</h3>\n<p><code>gradlew</code>는 <strong>Gradle Wrapper</strong> — 프로젝트에 고정된 Gradle 버전을 자동으로 내려받아 실행하는 스크립트입니다. 팀원마다 로컬에 설치된 Gradle 버전이 달라 빌드가 갈리는 일을 막습니다. npm으로 치면 <code>.nvmrc</code>로 Node 버전을 고정하는 것과 같은 동기. <em>로컬에 설치한 <code>gradle</code> 명령 대신 항상 <code>./gradlew</code>를 쓰는 게 원칙</em>입니다.</p>\n<div class=\"callout\">\n<span class=\"co-label\">실무 습관</span>\n<p>레포를 받으면 첫 명령은 <code>./gradlew build</code>. wrapper가 알아서 맞는 Gradle 버전을 받고, 의존성을 해석하고, 컴파일·테스트까지 돕니다. Windows는 <code>gradlew.bat</code>, macOS/Linux는 <code>./gradlew</code>. 실행 권한이 없다고 나오면 <code>chmod +x gradlew</code>.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"gradle-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">GRADLE-02</span><h2>의존성 추가</h2></div>\n<p class=\"lede\">라이브러리 추가는 <code>dependencies { }</code> 블록에 한 줄을 적는 일입니다. npm처럼 CLI로 추가하는 게 아니라 <em>파일을 직접 편집</em>한다는 게 가장 큰 차이입니다. 적고 나면 IDE가 새로고침하거나 빌드 시 자동으로 받습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">build.gradle — dependencies 블록</span>\ndependencies {<br>\n&nbsp;&nbsp;<span class=\"seg\">implementation</span> <span class=\"seg2\">'org.springframework.boot:spring-boot-starter-web:3.3.1'</span><br>\n&nbsp;&nbsp;<span class=\"seg\">implementation</span> <span class=\"seg2\">'com.google.guava:guava:33.2.1-jre'</span><br>\n&nbsp;&nbsp;<span class=\"seg\">testImplementation</span> <span class=\"seg2\">'org.springframework.boot:spring-boot-starter-test'</span><br>\n}\n</div>\n<h3><span class=\"h3-tag\">2.1</span>좌표 — group:name:version</h3>\n<p>모든 의존성은 <strong>좌표(coordinates)</strong>로 식별됩니다 — <code>group:name:version</code> 세 부분. npm의 <code>@scope/package@version</code>과 같은 개념이지만 group이 보통 역도메인(<code>org.springframework.boot</code>)입니다.</p>\n<table>\n<tr><th>부분</th><th>예시</th><th>npm 대응</th></tr>\n<tr><td><code>group</code></td><td><code>org.springframework.boot</code></td><td>scope(<code>@angular</code>)에 가까움 — 조직/네임스페이스</td></tr>\n<tr><td><code>name</code></td><td><code>spring-boot-starter-web</code></td><td>패키지 이름</td></tr>\n<tr><td><code>version</code></td><td><code>3.3.1</code></td><td>버전(생략 가능 — ch4)</td></tr>\n</table>\n<h3><span class=\"h3-tag\">2.2</span>Maven Central에서 좌표 찾기</h3>\n<p>라이브러리 좌표는 <code>search.maven.org</code> 또는 <code>mvnrepository.com</code>에서 검색합니다. 라이브러리를 고르면 빌드 도구별 스니펫(Gradle Groovy / Kotlin / Maven)을 그대로 복사할 수 있습니다 — npm 페이지에서 <code>npm install ...</code> 줄을 복사하는 것과 동선이 같습니다.</p>\n<div class=\"callout warn\">\n<span class=\"co-label\">의존성 저장소(repository)는 어디서?</span>\n<p>의존성을 어디서 받을지는 <code>build.gradle</code>(또는 <code>settings.gradle</code>의 <code>dependencyResolutionManagement</code>)의 <code>repositories { mavenCentral() }</code>가 정합니다. npm registry에 해당하는 게 <strong>Maven Central</strong>. 사내 라이브러리를 쓴다면 회사 Nexus/Artifactory 주소를 <code>maven { url '...' }</code>로 추가합니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"gradle-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">GRADLE-03</span><h2>의존성 스코프</h2></div>\n<p class=\"lede\">npm의 <code>dependencies</code> vs <code>devDependencies</code>가 둘로 갈리는 데 비해, Gradle은 더 세밀합니다 — <em>이 라이브러리를 언제(컴파일/런타임/테스트) 쓰고, 다른 모듈에 노출할지</em>까지 구분합니다. 이 구분이 빌드 속도와 모듈 캡슐화를 좌우합니다.</p>\n<table>\n<tr><th>configuration</th><th>언제 쓰나</th><th>npm 대응</th></tr>\n<tr><td><code>implementation</code></td><td>컴파일·런타임 모두 필요. <b>기본값</b> — 대부분 이걸 씀</td><td><code>dependencies</code></td></tr>\n<tr><td><code>api</code></td><td>컴파일·런타임 필요 + <b>이 모듈을 쓰는 쪽에도 전파</b>(라이브러리 모듈에서만)</td><td>(직접 대응 없음)</td></tr>\n<tr><td><code>compileOnly</code></td><td>컴파일에만 필요, 런타임 산출물엔 미포함(예: lombok, 서블릿 API)</td><td><code>devDependencies</code> 일부</td></tr>\n<tr><td><code>runtimeOnly</code></td><td>런타임에만 필요, 컴파일 땐 불필요(예: DB 드라이버 <code>runtimeOnly 'org.postgresql:postgresql'</code>)</td><td>(런타임 전용)</td></tr>\n<tr><td><code>testImplementation</code></td><td>테스트 코드 컴파일·실행에만</td><td><code>devDependencies</code>(테스트)</td></tr>\n<tr><td><code>annotationProcessor</code></td><td>컴파일 시 코드 생성(예: lombok, MapStruct, Spring 설정 메타)</td><td>(빌드타임 코드젠)</td></tr>\n</table>\n<h3><span class=\"h3-tag\">3.1</span>implementation vs api — 핵심 차이</h3>\n<p>둘 다 컴파일·런타임에 쓰지만 <strong>전파(transitivity) 노출</strong>이 다릅니다. 멀티모듈일 때만 의미가 있습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">A 모듈이 guava를 쓰고, B가 A를 의존할 때</span>\n<span class=\"seg\">implementation</span> 'guava' <span class=\"dim\">→ B는 guava를 직접 못 봄 (A 내부에 캡슐화)</span><br>\n<span class=\"seg\">api</span> 'guava'&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp; <span class=\"dim\">→ B도 guava를 컴파일 시 직접 사용 가능 (공개 전파)</span>\n</div>\n<p>기본은 항상 <code>implementation</code>입니다 — 캡슐화가 잘 되고, 의존성이 바뀌어도 그 모듈을 쓰는 쪽을 재컴파일할 필요가 줄어 빌드가 빠릅니다. <code>api</code>는 \"내 public API의 타입이 이 라이브러리 타입을 노출한다\"(예: 메서드 반환 타입이 guava의 <code>ImmutableList</code>)일 때만 씁니다.</p>\n<div class=\"callout warn\">\n<span class=\"co-label\">잘못 고르면</span>\n<p>전부 <code>api</code>로 두면 모든 모듈이 서로의 의존성을 보게 돼 캡슐화가 무너지고 빌드가 느려집니다. 반대로 노출해야 할 타입을 <code>implementation</code>에 두면 그 모듈을 쓰는 쪽에서 \"타입을 찾을 수 없다\" 컴파일 에러가 납니다. <em>의심되면 <code>implementation</code>, 컴파일 에러가 나면 그때 <code>api</code>로 승격.</em></p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"gradle-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">GRADLE-04</span><h2>버전 관리</h2></div>\n<p class=\"lede\">버전을 어디에 어떻게 적느냐가 유지보수의 질을 가릅니다. Spring Boot는 버전을 <em>대신 정해주고</em>, version catalog는 버전을 <em>한 곳에 모읍니다</em>. 둘 다 \"버전 숫자가 코드 여기저기 흩어지는\" 문제를 푸는 도구입니다.</p>\n<h3><span class=\"h3-tag\">4.1</span>Spring Boot 의존성 관리 — 버전 생략</h3>\n<p><code>io.spring.dependency-management</code> 플러그인(또는 Spring Boot 플러그인)이 적용되면, Spring이 검증한 라이브러리들은 <strong>버전을 적지 않아도</strong> 됩니다. Spring Boot의 BOM(Bill of Materials)이 서로 호환되는 버전 세트를 보장합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">버전을 생략한 의존성</span>\ndependencies {<br>\n&nbsp;&nbsp;<span class=\"seg\">implementation</span> <span class=\"seg2\">'org.springframework.boot:spring-boot-starter-web'</span> <span class=\"dim\">// 버전 X</span><br>\n&nbsp;&nbsp;<span class=\"seg\">implementation</span> <span class=\"seg2\">'org.springframework.boot:spring-boot-starter-data-jpa'</span><br>\n&nbsp;&nbsp;<span class=\"seg\">runtimeOnly</span> <span class=\"seg2\">'org.postgresql:postgresql'</span> <span class=\"dim\">// 버전도 BOM이 관리</span><br>\n}\n</div>\n<p>버전이 보이지 않아 처음엔 당황스럽지만, Spring Boot 버전 하나만 올리면 수십 개 라이브러리가 호환 세트로 함께 올라간다는 게 핵심 이점입니다. BOM에 없는 라이브러리만 명시적으로 버전을 적으면 됩니다.</p>\n<h3><span class=\"h3-tag\">4.2</span>version catalog — libs.versions.toml</h3>\n<p>여러 모듈에서 같은 라이브러리를 쓸 때 버전을 한 곳에서 관리하는 표준 방식이 <strong>version catalog</strong>입니다. <code>gradle/libs.versions.toml</code> 파일에 버전·라이브러리를 정의하고, 빌드 스크립트에서 <code>libs.xxx</code>로 참조합니다. npm의 lockfile + 중앙 관리 느낌.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">gradle/libs.versions.toml</span>\n[versions]<br>\n&nbsp;&nbsp;guava = <span class=\"seg2\">\"33.2.1-jre\"</span><br>\n<br>\n[libraries]<br>\n&nbsp;&nbsp;guava = { module = <span class=\"seg2\">\"com.google.guava:guava\"</span>, version.ref = <span class=\"seg2\">\"guava\"</span> }<br>\n<br>\n<span class=\"sc-label\">build.gradle — 참조</span>\ndependencies {<br>\n&nbsp;&nbsp;<span class=\"seg\">implementation</span> <span class=\"seg2\">libs.guava</span><br>\n}\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">언제 무엇</span>\n<p>단일 모듈 + Spring Boot라면 BOM만으로 충분 — version catalog는 과합니다. <em>멀티모듈에서 여러 모듈이 같은 라이브러리 버전을 공유</em>해야 할 때 catalog가 진가를 냅니다. 버전 업그레이드가 <code>.toml</code> 한 줄 수정으로 끝납니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"gradle-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">GRADLE-05</span><h2>플러그인</h2></div>\n<p class=\"lede\">플러그인은 Gradle에 <em>능력</em>을 더합니다 — Java 컴파일, Spring Boot 패키징, 의존성 버전 관리 같은 기능이 플러그인으로 들어옵니다. <code>plugins { }</code> 블록에 선언하며, 보통 파일 맨 위에 둡니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">build.gradle — plugins 블록</span>\nplugins {<br>\n&nbsp;&nbsp;id <span class=\"seg2\">'java'</span><br>\n&nbsp;&nbsp;id <span class=\"seg2\">'org.springframework.boot'</span> version <span class=\"seg2\">'3.3.1'</span><br>\n&nbsp;&nbsp;id <span class=\"seg2\">'io.spring.dependency-management'</span> version <span class=\"seg2\">'1.1.5'</span><br>\n}\n</div>\n<table>\n<tr><th>플러그인</th><th>하는 일</th></tr>\n<tr><td><code>java</code></td><td>Java 컴파일·테스트·JAR 생성 task 추가. <code>compileJava</code>, <code>test</code>, <code>jar</code> 등이 생김(코어 플러그인이라 version 불필요)</td></tr>\n<tr><td><code>org.springframework.boot</code></td><td>실행 가능한 fat JAR 패키징(<code>bootJar</code>), 앱 실행(<code>bootRun</code>), Spring Boot BOM 제공</td></tr>\n<tr><td><code>io.spring.dependency-management</code></td><td>BOM 기반 버전 관리 활성화 — 이게 있어야 ch4의 \"버전 생략\"이 동작</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">코어 vs 커뮤니티 플러그인</span>\n<p><code>java</code>처럼 Gradle에 내장된 <strong>코어 플러그인</strong>은 <code>version</code>이 필요 없습니다. 외부에서 받는 플러그인(<code>org.springframework.boot</code> 등)은 <code>version</code>을 명시해야 Gradle Plugin Portal에서 받아옵니다. Spring Initializr로 프로젝트를 생성하면 이 세 줄이 기본으로 들어가 있습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"gradle-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">GRADLE-06</span><h2>의존성 확인·트러블슈팅</h2></div>\n<p class=\"lede\">\"이 라이브러리가 왜 들어왔지\", \"버전이 왜 이게 됐지\"를 추적하는 도구들. transitive dependency(간접 의존성)가 얽히면 눈으로는 못 풉니다 — Gradle이 답을 알려줍니다.</p>\n<table>\n<tr><th>명령</th><th>의미 / 형태</th></tr>\n<tr><td><code>./gradlew dependencies</code></td><td>전체 의존성 트리 출력. <code>--configuration runtimeClasspath</code>로 특정 스코프만</td></tr>\n<tr><td><code>./gradlew dependencyInsight --dependency guava</code></td><td><b>특정 라이브러리가 왜·어떤 버전으로 들어왔는지</b> 역추적. 충돌 진단의 핵심</td></tr>\n<tr><td><code>./gradlew :app:dependencies</code></td><td>멀티모듈에서 특정 모듈(<code>app</code>)의 트리만</td></tr>\n<tr><td><code>./gradlew build --refresh-dependencies</code></td><td>캐시 무시하고 의존성을 다시 받음(레포 갱신 안 잡힐 때)</td></tr>\n</table>\n<h3><span class=\"h3-tag\">6.1</span>버전 충돌과 강제</h3>\n<p>서로 다른 라이브러리가 같은 의존성의 다른 버전을 요구하면 충돌합니다. Gradle의 기본 전략은 <strong>가장 높은 버전 선택</strong>(npm의 중첩 설치와 달리 JVM은 클래스패스에 한 버전만 존재 가능). 특정 버전으로 고정해야 하면 강제합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">build.gradle — 버전 강제</span>\ndependencies {<br>\n&nbsp;&nbsp;<span class=\"seg\">implementation</span>(<span class=\"seg2\">'com.google.guava:guava'</span>) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;version { strictly <span class=\"seg2\">'33.2.1-jre'</span> } <span class=\"dim\">// 이 버전으로 고정</span><br>\n&nbsp;&nbsp;}<br>\n}<br>\n<br>\n<span class=\"dim\">// 또는 전역 resolutionStrategy</span><br>\nconfigurations.all {<br>\n&nbsp;&nbsp;resolutionStrategy.force <span class=\"seg2\">'com.google.guava:guava:33.2.1-jre'</span><br>\n}\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">디버깅 순서</span>\n<p>\"클래스를 못 찾는다 / 메서드가 없다\"(<code>NoSuchMethodError</code>)는 거의 버전 충돌입니다. ① <code>dependencyInsight --dependency 문제라이브러리</code>로 어떤 버전이 선택됐고 누가 끌고 왔는지 확인 → ② 원치 않는 transitive를 <code>exclude group: '...', module: '...'</code>로 빼거나 <code>strictly</code>로 고정. 추측으로 버전을 바꾸지 말고 트리를 먼저 보세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"gradle-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">GRADLE-07</span><h2>자주 쓰는 task</h2></div>\n<p class=\"lede\">Gradle은 \"task\" 단위로 동작합니다 — <code>npm run</code>의 스크립트에 해당. 핵심 몇 개만 손에 붙이면 일상은 충분합니다. 항상 <code>./gradlew</code>로 호출하세요.</p>\n<table>\n<tr><th>task</th><th>하는 일 / npm 대응</th></tr>\n<tr><td><code>./gradlew build</code></td><td>컴파일 + 테스트 + 패키징 전체. (≈ <code>npm run build</code> + test)</td></tr>\n<tr><td><code>./gradlew clean</code></td><td><code>build/</code> 산출물 삭제. 꼬였을 때 <code>clean build</code>로 처음부터</td></tr>\n<tr><td><code>./gradlew test</code></td><td>테스트만 실행. <code>--tests \"*.UserServiceTest\"</code>로 특정 테스트만</td></tr>\n<tr><td><code>./gradlew bootRun</code></td><td>Spring Boot 앱을 실행(개발 중 띄우기). (≈ <code>npm start</code>)</td></tr>\n<tr><td><code>./gradlew bootJar</code></td><td>실행 가능한 fat JAR 생성 → <code>java -jar build/libs/*.jar</code>로 배포</td></tr>\n<tr><td><code>./gradlew tasks</code></td><td>사용 가능한 task 목록(설명 포함). 모를 땐 여기부터</td></tr>\n<tr><td><code>./gradlew --stop</code></td><td>백그라운드 Gradle 데몬 종료(메모리·캐시 꼬임 해소)</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">유용한 플래그</span>\n<p><code>--info</code>/<code>--debug</code>(상세 로그), <code>--stacktrace</code>(에러 스택), <code>-x test</code>(테스트 스킵 — 예: <code>build -x test</code>), <code>--offline</code>(네트워크 없이 캐시만). 빌드가 이상하게 빠르면 Gradle이 캐시한 결과를 재사용한 것 — 정상이지만 강제로 다시 돌리려면 <code>clean</code> 후 빌드.</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"gradle-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">GRADLE-08</span><h2>멀티모듈 기초</h2></div>\n<p class=\"lede\">앱이 커지면 하나의 빌드를 여러 모듈로 쪼갭니다 — <code>core</code>(도메인), <code>api</code>(웹), <code>batch</code>(배치) 식으로. npm의 monorepo/workspaces와 같은 동기. <code>settings.gradle</code>이 모듈 구성을, 각 모듈의 <code>build.gradle</code>이 자기 의존성을 책임집니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">settings.gradle — 모듈 포함</span>\nrootProject.name = <span class=\"seg2\">'my-app'</span><br>\ninclude <span class=\"seg2\">'core'</span>, <span class=\"seg2\">'api'</span>, <span class=\"seg2\">'batch'</span>\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">api/build.gradle — 다른 모듈 의존</span>\ndependencies {<br>\n&nbsp;&nbsp;<span class=\"seg\">implementation</span> <span class=\"seg2\">project(':core')</span> <span class=\"dim\">// core 모듈을 의존</span><br>\n&nbsp;&nbsp;<span class=\"seg\">implementation</span> <span class=\"seg2\">'org.springframework.boot:spring-boot-starter-web'</span><br>\n}\n</div>\n<p>외부 라이브러리는 좌표(<code>group:name:version</code>)로, <em>같은 빌드 안의 내부 모듈</em>은 <code>project(':core')</code>로 참조합니다. 콜론(<code>:</code>)은 프로젝트 경로 구분자 — 루트 기준 경로입니다. 여기서 ch3의 <code>api</code> vs <code>implementation</code> 구분이 실제로 의미를 갖습니다.</p>\n<div class=\"callout warn\">\n<span class=\"co-label\">순환 의존 금지</span>\n<p><code>api → core</code>는 되지만 동시에 <code>core → api</code>를 만들면 순환 의존(circular dependency)으로 빌드가 실패합니다. 모듈 의존은 <em>한 방향</em>으로 흐르게 설계하세요 — 보통 <code>core</code>는 아무도 의존하지 않는 가장 안쪽에 둡니다. 공통 코드는 별도 모듈로 빼서 양쪽이 그것을 의존하게 합니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"gradle-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">GRADLE-09</span><h2>치트시트 — 자주 쓰는 한 줄</h2></div>\n<p class=\"lede\">실전에서 반복되는 조합들. 외우기보다 \"이런 게 가능하다\"를 알아두고 필요할 때 찾으세요.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>의존성 추가</b><span>dependencies</span></div><div class=\"g-def\"><code>implementation 'group:name:version'</code> 를 <code>dependencies {}</code> 안에. Spring Boot면 version 생략 가능</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>기본 스코프</b><span>implementation</span></div><div class=\"g-def\">대부분 <code>implementation</code>. 컴파일만=<code>compileOnly</code>, 런타임만=<code>runtimeOnly</code>, 테스트=<code>testImplementation</code>, 코드젠=<code>annotationProcessor</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>api vs implementation</b><span>전파 여부</span></div><div class=\"g-def\"><code>api</code>는 의존하는 쪽에도 노출, <code>implementation</code>은 캡슐화. 기본은 <code>implementation</code>, public 타입 노출 시에만 <code>api</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>DB 드라이버</b><span>runtimeOnly</span></div><div class=\"g-def\"><code>runtimeOnly 'org.postgresql:postgresql'</code> — 컴파일엔 불필요, 실행 시에만 필요</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>version catalog</b><span>libs.versions.toml</span></div><div class=\"g-def\"><code>gradle/libs.versions.toml</code>에 정의 → <code>implementation libs.guava</code>로 참조. 멀티모듈 버전 중앙 관리</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>의존성 트리</b><span>dependencies</span></div><div class=\"g-def\"><code>./gradlew dependencies</code> — 전체 트리. <code>--configuration runtimeClasspath</code>로 스코프 한정</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>왜 이 버전?</b><span>dependencyInsight</span></div><div class=\"g-def\"><code>./gradlew dependencyInsight --dependency guava</code> — 누가 끌고 왔고 어떤 버전이 선택됐는지</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>버전 강제</b><span>resolutionStrategy</span></div><div class=\"g-def\"><code>resolutionStrategy.force 'group:name:version'</code> 또는 의존성에 <code>version { strictly '...' }</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>캐시 갱신</b><span>--refresh-dependencies</span></div><div class=\"g-def\"><code>./gradlew build --refresh-dependencies</code> — 레포 변경이 안 잡힐 때 강제 재다운로드</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>앱 실행/패키징</b><span>bootRun / bootJar</span></div><div class=\"g-def\">개발 실행 <code>./gradlew bootRun</code>, 배포 JAR <code>./gradlew bootJar</code> → <code>java -jar build/libs/*.jar</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>처음부터 빌드</b><span>clean build</span></div><div class=\"g-def\"><code>./gradlew clean build</code> — 산출물 지우고 새로. 테스트 스킵은 <code>-x test</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>데몬 종료</b><span>--stop</span></div><div class=\"g-def\"><code>./gradlew --stop</code> — 빌드가 이상하게 꼬이거나 캐시 문제 의심 시 데몬 재시작</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>내부 모듈 의존</b><span>project(':core')</span></div><div class=\"g-def\"><code>implementation project(':core')</code> — 같은 빌드의 다른 모듈. <code>settings.gradle</code>에 <code>include 'core'</code> 필요</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>wrapper 우선</b><span>./gradlew</span></div><div class=\"g-def\">로컬 <code>gradle</code> 대신 항상 <code>./gradlew</code> — 팀과 같은 Gradle 버전 보장. task 목록은 <code>./gradlew tasks</code></div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">학습 순서 제안</span>\n<p>전부 외우려 하지 마세요. 손에 먼저 붙일 것: <code>./gradlew build</code> · <code>bootRun</code> · <code>dependencies</code> · <code>dependencyInsight</code> · <code>implementation</code> 스코프 감각. npm 하던 머릿속 지도(<code>package.json</code>≈<code>build.gradle</code>, <code>node_modules</code>≈전역 캐시, <code>npm run</code>≈<code>./gradlew task</code>)를 먼저 옮기면 나머지는 필요할 때 이 가이드에서 찾으면 됩니다. 버전 충돌이 의심되면 추측 말고 <code>dependencyInsight</code>부터.</p>\n</div>\n</section>\n\n<footer>\nGRADLE DEPENDENCY · BUILD GUIDE · V1 · 2026-06<br>\nSCOPE : DEPENDENCY · BUILD · STACK : Gradle 8.x · Spring Boot 3.x · Java<br>\nNOTE : Groovy DSL(build.gradle) 기준 — Kotlin DSL(.gradle.kts)은 문법 차이 있음 · COMPANION : LINUX/SHELL COMMANDS HANDBOOK\n</footer>\n\n<section id=\"doc-packages\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>패키지·버전 매니저</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : PKG-GUIDE-V1</span>\n    <span>SCOPE : npm · pnpm · nvm · mise</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>패키지·버전 매니저<br>실무 가이드</h1>\n  <p class=\"hero-sub\">자주 혼동되는 두 범주를 가른다 — <strong>패키지 매니저</strong>(npm·pnpm)와 <strong>런타임 버전 매니저</strong>(nvm·mise). 전자는 라이브러리를 설치하고, 후자는 Node 자체의 버전을 바꿉니다. Gradle 가이드의 Node/JS 짝.</p>\n  <div class=\"hero-meta\">ENV : macOS · zsh · mise · npm/pnpm<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"packages-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">PKG-01</span><h2>두 범주를 구분하라</h2></div>\n<p class=\"lede\">제일 먼저 잡을 것: <em>\"라이브러리를 설치하는 도구\"</em>와 <em>\"Node 자체의 버전을 바꾸는 도구\"</em>는 다른 범주입니다. 둘 다 \"매니저\"라 불려서 섞이지만, 푸는 문제가 완전히 다릅니다.</p>\n<table>\n<tr><th>범주</th><th>하는 일</th><th>도구</th><th>설정 파일</th></tr>\n<tr><td><b>패키지 매니저</b></td><td>프로젝트 의존성(라이브러리) 설치·관리</td><td>npm · pnpm · yarn</td><td><code>package.json</code> + lockfile</td></tr>\n<tr><td><b>런타임 버전 매니저</b></td><td>Node(런타임) 자체의 버전 설치·전환</td><td>nvm · mise · fnm · Volta</td><td><code>.nvmrc</code> · <code>.mise.toml</code></td></tr>\n</table>\n<p>React 프로젝트로 비유하면 이렇습니다 — <code>npm install react</code>는 <em>react 라이브러리</em>를 끌어오는 일(패키지 매니저), <code>mise use node@22</code>는 <em>이 프로젝트를 Node 22에서 돌리겠다</em>는 일(버전 매니저). 한쪽은 <code>node_modules</code>를 채우고, 다른 쪽은 <code>node</code> 명령이 가리키는 실행 파일을 바꿉니다.</p>\n<div class=\"callout gm\">\n<span class=\"co-label\">JAVA 대응 — Gradle 가이드와 짝</span>\n<p>Java 세계로 옮기면 정확히 같은 두 축입니다. 패키지 매니저 = <strong>Gradle/Maven</strong>(<code>build.gradle</code>의 dependencies 블록이 라이브러리를 끌어옴). 런타임 버전 매니저 = <strong>mise/SDKMAN</strong>(JDK 17 vs 21 전환). 그래서 mise 하나로 Node와 Java 버전을 동시에 고정할 수 있습니다(→ PKG-08). 의존성 해석과 런타임 전환은 별개의 일이라는 감각이 핵심입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"packages-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">PKG-02</span><h2>npm 기본</h2></div>\n<p class=\"lede\">npm은 Node에 기본 내장된 패키지 매니저입니다. 새 도구를 배우기 전에, 모든 매니저가 공유하는 기반인 <code>package.json</code>·semver·lockfile부터 정확히 잡으세요.</p>\n<h3><span class=\"h3-tag\">2.1</span>package.json과 scripts</h3>\n<p><code>package.json</code>은 프로젝트의 명세서입니다 — 의존성 목록, 실행 스크립트, 메타데이터. 익숙하겠지만 <code>dependencies</code>(런타임에 필요)와 <code>devDependencies</code>(빌드·테스트에만 필요)의 구분이 배포 산출물 크기를 좌우합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">PACKAGE.JSON — 핵심 필드</span>\n{<br>\n&nbsp;&nbsp;<span class=\"seg2\">\"scripts\"</span>: { <span class=\"seg\">\"dev\"</span>: \"next dev\", <span class=\"seg\">\"build\"</span>: \"next build\" },<br>\n&nbsp;&nbsp;<span class=\"seg2\">\"dependencies\"</span>: { <span class=\"dim\">\"react\"</span>: <span class=\"seg\">\"^18.3.0\"</span> },<br>\n&nbsp;&nbsp;<span class=\"seg2\">\"devDependencies\"</span>: { <span class=\"dim\">\"typescript\"</span>: <span class=\"seg\">\"~5.4.0\"</span> }<br>\n}<br>\n<span class=\"dim\">실행: npm run dev &nbsp;(dev/start/test 는 run 생략 가능 — npm test)</span>\n</div>\n<h3><span class=\"h3-tag\">2.2</span>semver — ^ 와 ~ 의 차이</h3>\n<p>버전 앞 기호는 <em>\"업데이트를 어디까지 허용하는가\"</em>의 범위 지정입니다. semver는 <code>MAJOR.MINOR.PATCH</code> (예: <code>18.3.1</code>) — MAJOR는 호환성 깨짐, MINOR는 기능 추가, PATCH는 버그 수정.</p>\n<table>\n<tr><th>표기</th><th>허용 범위</th><th>의미</th></tr>\n<tr><td><code>^18.3.0</code></td><td>18.3.0 ~ 18.x.x (19 미만)</td><td>MINOR·PATCH 업데이트 허용 (npm 기본)</td></tr>\n<tr><td><code>~18.3.0</code></td><td>18.3.0 ~ 18.3.x (18.4 미만)</td><td>PATCH만 허용 (더 보수적)</td></tr>\n<tr><td><code>18.3.0</code></td><td>18.3.0 고정</td><td>정확히 그 버전만</td></tr>\n<tr><td><code>*</code> / <code>latest</code></td><td>아무 버전</td><td>위험 — 재현성 깨짐, 쓰지 말 것</td></tr>\n</table>\n<h3><span class=\"h3-tag\">2.3</span>install vs ci</h3>\n<table>\n<tr><th>명령</th><th>동작 / 언제</th></tr>\n<tr><td><code>npm install</code></td><td>package.json 기준으로 설치 — 필요하면 <em>lockfile을 갱신</em>. 로컬 개발에서 의존성 추가·변경할 때</td></tr>\n<tr><td><code>npm install pkg</code></td><td>패키지 추가. <code>-D</code>는 devDependencies로, <code>-g</code>는 전역</td></tr>\n<tr><td><code>npm ci</code></td><td><b>lockfile 그대로</b> 설치 — node_modules를 지우고 lock대로만. 빠르고 결정적. <em>CI·배포 전용</em></td></tr>\n<tr><td><code>npm run &lt;script&gt;</code></td><td>scripts에 정의한 명령 실행</td></tr>\n<tr><td><code>npx &lt;pkg&gt;</code></td><td>설치 없이 패키지 실행 (예: <code>npx create-next-app</code>)</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">install과 ci를 헷갈리지 말 것</span>\n<p><code>npm install</code>은 상황에 따라 <code>package-lock.json</code>을 <em>고쳐 씁니다</em> — semver 범위 안에 새 버전이 나왔으면 올려버릴 수 있습니다. CI에서 이걸 쓰면 \"어제는 됐는데 오늘 빌드가 깨짐\"이 생깁니다. CI·배포에서는 항상 <code>npm ci</code> — lockfile과 package.json이 어긋나면 아예 에러를 내고, lock에 적힌 버전만 정확히 설치합니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"packages-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">PKG-03</span><h2>pnpm</h2></div>\n<p class=\"lede\">pnpm은 npm과 같은 일을 하되 <em>디스크와 속도</em>에서 다른 설계를 택했습니다. 명령어는 거의 호환돼서 갈아타는 비용이 작습니다.</p>\n<h3><span class=\"h3-tag\">3.1</span>왜 빠르고 디스크를 아끼나</h3>\n<p>핵심은 <strong>content-addressable store + hardlink</strong>입니다. npm은 프로젝트마다 <code>node_modules</code>에 패키지를 통째로 복사하지만, pnpm은 전역 store(<code>~/.local/share/pnpm/store</code>) 한 곳에만 실제 파일을 두고, 각 프로젝트의 <code>node_modules</code>에는 그 파일로의 <em>hardlink</em>만 겁니다. 같은 버전을 10개 프로젝트가 써도 디스크에는 한 벌만 존재합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">DISK MODEL — npm vs pnpm</span>\n<span class=\"dim\">npm :</span> projectA/node_modules/react <span class=\"seg\">(복사본)</span><br>\n<span class=\"dim\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span> projectB/node_modules/react <span class=\"seg\">(또 복사본)</span><br>\n<br>\n<span class=\"dim\">pnpm:</span> ~/.pnpm-store/react <span class=\"seg2\">(원본 1벌)</span><br>\n<span class=\"dim\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span> projectA/node_modules/react ──▶ <span class=\"seg2\">hardlink</span><br>\n<span class=\"dim\">&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;</span> projectB/node_modules/react ──▶ <span class=\"seg2\">hardlink</span>\n</div>\n<h3><span class=\"h3-tag\">3.2</span>엄격한 node_modules — 유령 의존성 차단</h3>\n<p>npm은 의존성을 <code>node_modules</code> 최상단에 평평하게(flat) 깝니다. 그 부작용으로, <code>package.json</code>에 직접 선언하지 않은 패키지도 <code>import</code>가 됩니다 — <strong>phantom dependency(유령 의존성)</strong>. 어느 날 의존성 트리가 바뀌면 그 import가 소리 없이 깨집니다. pnpm은 선언한 패키지만 접근 가능하게 막아서 이 함정을 원천 차단합니다.</p>\n<h3><span class=\"h3-tag\">3.3</span>npm → pnpm 명령 대응</h3>\n<table>\n<tr><th>npm</th><th>pnpm</th><th>의미</th></tr>\n<tr><td><code>npm install</code></td><td><code>pnpm install</code></td><td>전체 설치</td></tr>\n<tr><td><code>npm install react</code></td><td><code>pnpm add react</code></td><td>패키지 추가</td></tr>\n<tr><td><code>npm install -D ts</code></td><td><code>pnpm add -D ts</code></td><td>devDependency 추가</td></tr>\n<tr><td><code>npm uninstall react</code></td><td><code>pnpm remove react</code></td><td>패키지 제거</td></tr>\n<tr><td><code>npm run dev</code></td><td><code>pnpm dev</code></td><td>스크립트 실행 (run 생략 가능)</td></tr>\n<tr><td><code>npm ci</code></td><td><code>pnpm install --frozen-lockfile</code></td><td>lockfile 고정 설치</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">lockfile은 pnpm-lock.yaml</span>\n<p>pnpm은 <code>pnpm-lock.yaml</code>을 씁니다 — npm의 <code>package-lock.json</code>과 형식이 다릅니다. 둘은 호환되지 않으니 한 프로젝트에 둘이 공존하면 안 됩니다(→ PKG-04). 기존 npm 프로젝트를 옮길 때는 <code>pnpm import</code>로 <code>package-lock.json</code>을 읽어 <code>pnpm-lock.yaml</code>을 만들면 버전이 보존됩니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"packages-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">PKG-04</span><h2>npm vs pnpm vs yarn</h2></div>\n<p class=\"lede\">셋 다 같은 일을 합니다 — 라이브러리 설치. 선택은 취향이 아니라 <em>팀 합의</em>의 문제입니다. 한 프로젝트엔 반드시 하나만.</p>\n<table>\n<tr><th>기준</th><th>npm</th><th>pnpm</th><th>yarn (berry)</th></tr>\n<tr><td>설치 속도</td><td>보통</td><td><b>빠름</b></td><td>빠름</td></tr>\n<tr><td>디스크 사용</td><td>많음</td><td><b>적음 (hardlink)</b></td><td>중간 (PnP는 적음)</td></tr>\n<tr><td>엄격성</td><td>느슨 (유령 의존성)</td><td><b>엄격</b></td><td>엄격 (PnP)</td></tr>\n<tr><td>모노레포</td><td>workspaces 지원</td><td><b>강력</b></td><td>강력</td></tr>\n<tr><td>설치</td><td>Node 내장</td><td>별도 (corepack)</td><td>별도 (corepack)</td></tr>\n<tr><td>lockfile</td><td>package-lock.json</td><td>pnpm-lock.yaml</td><td>yarn.lock</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">lockfile은 섞이지 않는다</span>\n<p>세 매니저의 lockfile은 <strong>서로 호환되지 않습니다</strong>. 한 사람은 <code>npm install</code>, 다른 사람은 <code>pnpm install</code>을 쓰면 <code>package-lock.json</code>과 <code>pnpm-lock.yaml</code>이 둘 다 생기고 의존성 버전이 갈라집니다 — \"내 PC에선 되는데\"의 전형적 원인. 팀은 <em>매니저를 하나로 통일</em>하고, <code>package.json</code>의 <code>packageManager</code> 필드(예: <code>\"packageManager\": \"pnpm@9.1.0\"</code>)에 박아 corepack이 강제하게 하세요.</p>\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">실무 권고</span>\n<p>새 프로젝트라면 pnpm을 기본값으로 두는 게 합리적입니다 — 빠르고, 디스크를 아끼고, 유령 의존성을 막아줍니다. 기존 npm 프로젝트를 굳이 바꿀 필요는 없습니다. 중요한 건 도구의 우열이 아니라 <em>팀 전체가 같은 하나</em>를 쓰는 것입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"packages-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">PKG-05</span><h2>lockfile과 재현성</h2></div>\n<p class=\"lede\">lockfile은 <em>\"누가 언제 설치해도 같은 의존성 트리가 나오게\"</em> 만드는 장치입니다. \"내 PC만 됨\"을 막는 가장 직접적인 도구.</p>\n<p><code>package.json</code>의 <code>^18.3.0</code>은 <em>범위</em>일 뿐 정확한 버전이 아닙니다. 그래서 설치 시점에 따라 18.3.0이 올 수도, 18.4.2가 올 수도 있습니다. lockfile은 실제로 설치된 <strong>정확한 버전과 전체 의존성 트리(transitive dependency 포함)</strong>를 기록해, 다음 설치가 그대로 재현되게 합니다.</p>\n<div class=\"flow\">\n<span class=\"step\">package.json<br>^18.3.0 (범위)</span>\n<span class=\"arr\">→ 해석 →</span>\n<span class=\"step hl\">lockfile<br>18.3.1 (정확)</span>\n<span class=\"arr\">→ 재현 →</span>\n<span class=\"step\">모든 환경<br>동일 트리</span>\n</div>\n<table>\n<tr><th>해야 할 것</th><th>이유</th></tr>\n<tr><td>lockfile을 <b>git에 커밋</b></td><td>팀·CI가 같은 버전을 받게 — 재현성의 전제</td></tr>\n<tr><td>CI에선 <code>npm ci</code> / <code>pnpm install --frozen-lockfile</code></td><td>lockfile을 <em>고치지 않고</em> 그대로만 설치 — 결정적 빌드</td></tr>\n<tr><td>의존성 추가·변경 후 lockfile도 함께 커밋</td><td>package.json과 lock의 어긋남 방지</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">lockfile을 무시하면</span>\n<p>lockfile을 <code>.gitignore</code>에 넣거나 CI에서 <code>npm install</code>을 쓰면, transitive dependency의 PATCH 하나가 조용히 올라와 빌드를 깨거나 — 더 나쁘게는 — 공급망 공격(악성 버전 주입)에 노출됩니다. <strong>frozen-lockfile</strong>은 lockfile과 package.json이 불일치하면 설치를 거부해 이런 표류를 막습니다. lockfile은 빌드 산출물이 아니라 <em>소스의 일부</em>로 다루세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"packages-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">PKG-06</span><h2>워크스페이스(모노레포) 간단</h2></div>\n<p class=\"lede\">한 저장소 안에 여러 패키지(앱·라이브러리)를 두고 함께 관리하는 구조가 <em>모노레포</em>입니다. npm·pnpm 모두 workspaces로 지원합니다 — 여기서는 개념만.</p>\n<p>예를 들어 웹 앱, 모바일 앱, 둘이 공유하는 UI 컴포넌트 라이브러리를 한 저장소에 둡니다. workspaces를 쓰면 의존성을 루트에서 한 번에 설치하고, 패키지끼리 로컬 경로로 서로를 참조할 수 있습니다(<code>npm publish</code> 없이).</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">MONOREPO — 구조와 선언</span>\n<span class=\"dim\">my-repo/</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">package.json</span> <span class=\"dim\">← 루트 (workspaces 선언)</span><br>\n&nbsp;&nbsp;packages/<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">ui/</span> <span class=\"dim\">package.json</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">web/</span> <span class=\"dim\">package.json (ui 를 참조)</span><br>\n<br>\n<span class=\"dim\"># npm: 루트 package.json</span><br>\n<span class=\"seg2\">\"workspaces\"</span>: [<span class=\"seg\">\"packages/*\"</span>]<br>\n<span class=\"dim\"># pnpm: 별도 pnpm-workspace.yaml 파일에 선언</span>\n</div>\n<table>\n<tr><th>매니저</th><th>워크스페이스 선언</th></tr>\n<tr><td>npm</td><td><code>package.json</code>의 <code>\"workspaces\": [\"packages/*\"]</code></td></tr>\n<tr><td>pnpm</td><td>별도 <code>pnpm-workspace.yaml</code> 파일에 <code>packages:</code> 목록</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">언제 쓰나 — 그리고 언제 멈추나</span>\n<p>여러 패키지가 긴밀히 함께 바뀔 때(공유 컴포넌트·내부 SDK) 모노레포가 빛납니다. 규모가 커지면 빌드 캐시·태스크 그래프를 다루는 <code>Turborepo</code>·<code>Nx</code> 같은 도구를 얹습니다 — 다만 그건 진짜 필요해질 때 도입하세요. 작은 프로젝트에 처음부터 모노레포 도구를 까는 건 과설계입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"packages-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">PKG-07</span><h2>nvm — Node 버전 매니저</h2></div>\n<p class=\"lede\">여기부터는 다른 범주 — 라이브러리가 아니라 <em>Node 런타임 자체</em>의 버전을 바꾸는 도구입니다. nvm이 가장 오래되고 널리 알려진 선택지입니다.</p>\n<p>프로젝트 A는 Node 18, 프로젝트 B는 Node 22를 요구할 때, 시스템에 Node를 하나만 깔아두면 충돌합니다. nvm은 여러 Node 버전을 깔아두고 셸에서 전환하게 해줍니다.</p>\n<table>\n<tr><th>명령</th><th>의미</th></tr>\n<tr><td><code>nvm install 22</code></td><td>Node 22 설치</td></tr>\n<tr><td><code>nvm use 22</code></td><td>현재 셸에서 22로 전환</td></tr>\n<tr><td><code>nvm alias default 22</code></td><td>새 셸의 기본 버전을 22로</td></tr>\n<tr><td><code>nvm ls</code></td><td>설치된 버전 목록</td></tr>\n<tr><td><code>nvm use</code></td><td>현재 디렉터리의 <code>.nvmrc</code>에 적힌 버전으로</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">.NVMRC — 프로젝트 버전 고정</span>\n<span class=\"dim\"># 프로젝트 루트의 .nvmrc 파일 내용:</span><br>\n<span class=\"seg\">22</span><br>\n<br>\n<span class=\"dim\"># 진입 후 직접 적용해야 함:</span><br>\n$ nvm use <span class=\"dim\">→ Now using node v22.x</span>\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">nvm의 단점 — 느림·수동</span>\n<p>nvm은 셸 함수로 구현돼 있어 <code>~/.zshrc</code>에서 매번 로드되며 <em>셸 시작이 눈에 띄게 느려집니다</em>. 또 <code>.nvmrc</code>가 있어도 디렉터리에 들어갈 때 <strong>자동 전환이 안 됩니다</strong> — 매번 <code>nvm use</code>를 직접 쳐야 합니다(자동화하려면 별도 셸 훅 설정 필요). 이 두 가지 불편 때문에 fnm·mise 같은 더 빠른 대안으로 옮기는 흐름이 있습니다(→ PKG-08).</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"packages-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">PKG-08</span><h2>mise — 폴리글랏 버전 매니저</h2></div>\n<p class=\"lede\">mise는 Node만이 아니라 <em>여러 언어의 런타임을 하나로</em> 관리합니다 — nvm·pyenv·rbenv·SDKMAN을 한 도구로 대체. 디렉터리 진입 시 자동 전환이 기본이라 nvm의 두 단점을 동시에 해결합니다. 풀스택 프로젝트에서 Node와 Java 같은 여러 런타임을 함께 고정할 때 특히 유용합니다.</p>\n<h3><span class=\"h3-tag\">8.1</span>설치·전환 명령</h3>\n<table>\n<tr><th>명령</th><th>의미</th></tr>\n<tr><td><code>mise use node@22</code></td><td>현재 프로젝트에 Node 22 고정 (<code>.mise.toml</code>에 기록)</td></tr>\n<tr><td><code>mise install</code></td><td><code>.mise.toml</code>에 적힌 모든 런타임 설치</td></tr>\n<tr><td><code>mise use -g node@22</code></td><td>전역 기본값으로 (<code>-g</code>)</td></tr>\n<tr><td><code>mise ls</code></td><td>설치·활성 버전 목록</td></tr>\n<tr><td><code>mise exec -- node -v</code></td><td>mise 환경에서 일회성 실행</td></tr>\n</table>\n<h3><span class=\"h3-tag\">8.2</span>.mise.toml — Node·Java 한 파일에</h3>\n<p>nvm은 Node만, pyenv는 Python만 봅니다. mise는 한 파일에 여러 런타임을 선언해 — 풀스택으로 확장 중이라면 Node와 Java 버전을 한 곳에 고정할 수 있습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">.MISE.TOML — 프로젝트 루트</span>\n[<span class=\"seg2\">tools</span>]<br>\n<span class=\"seg\">node</span> = <span class=\"dim\">\"22\"</span><br>\n<span class=\"seg\">java</span> = <span class=\"dim\">\"temurin-21\"</span><br>\n<br>\n<span class=\"dim\"># 이 디렉터리에 들어가면 node·java 가 자동으로 이 버전</span>\n</div>\n<h3><span class=\"h3-tag\">8.3</span>자동 전환 — activate</h3>\n<p>핵심 한 줄. <code>~/.zshrc</code>에 아래를 넣으면, 디렉터리에 들어가는 순간 그 프로젝트의 <code>.mise.toml</code>을 읽어 <em>버전이 자동으로 바뀝니다</em> — nvm처럼 매번 명령을 칠 필요가 없습니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">~/.ZSHRC — 자동 전환 활성화</span>\neval <span class=\"dim\">\"$(</span>mise activate zsh<span class=\"dim\">)\"</span><br>\n<br>\n<span class=\"dim\"># chezmoi 로 .zshrc 관리 중이면:</span><br>\n$ chezmoi edit ~/.zshrc <span class=\"dim\">→ 위 줄 추가 →</span> chezmoi apply\n</div>\n<p>덤으로 <code>mise tasks</code>로 프로젝트 스크립트(빌드·린트 등)도 관리할 수 있습니다 — npm scripts와 비슷하지만 언어에 구애받지 않습니다. 여기서는 존재만 알아두세요.</p>\n<div class=\"callout gm\">\n<span class=\"co-label\">nvm 정리하고 mise로</span>\n<p>nvm과 mise를 동시에 켜두면 둘 다 <code>node</code> PATH를 건드려 충돌합니다. mise로 옮기면 <code>~/.zshrc</code>에서 nvm 로드 줄을 빼세요. mise는 nvm의 <code>.nvmrc</code>와 <code>.node-version</code>도 읽어주므로, 기존 프로젝트의 <code>.nvmrc</code>를 굳이 지우지 않아도 동작합니다 — 다만 새 프로젝트는 <code>.mise.toml</code>로 통일하는 게 깔끔합니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"packages-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">PKG-09</span><h2>치트시트</h2></div>\n<p class=\"lede\">전부 외우지 말고, 헷갈릴 때 여기서 찾으세요. 두 범주의 구분만 머리에 박혀 있으면 나머지는 조회로 충분합니다.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>두 범주 구분</b><span>two categories</span></div><div class=\"g-def\"><b>패키지 매니저</b>(npm·pnpm = 라이브러리 설치) vs <b>버전 매니저</b>(nvm·mise = Node 자체 버전 전환). 푸는 문제가 다름</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>npm ci</b><span>clean install</span></div><div class=\"g-def\">lockfile 그대로 결정적 설치. CI·배포 전용. <code>npm install</code>은 lock을 갱신할 수 있어 빌드에 부적합</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>semver ^ ~</b><span>range</span></div><div class=\"g-def\"><code>^18.3.0</code>=MINOR·PATCH 허용(19 미만) · <code>~18.3.0</code>=PATCH만(18.4 미만) · <code>18.3.0</code>=고정</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>pnpm 장점</b><span>why pnpm</span></div><div class=\"g-def\">content-addressable store + hardlink로 디스크 절약·빠름. 엄격한 node_modules로 유령 의존성 차단</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>유령 의존성</b><span>phantom dep</span></div><div class=\"g-def\">package.json에 선언 안 한 패키지가 import되는 현상(npm flat 구조 부작용). pnpm이 차단</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>lockfile</b><span>reproducibility</span></div><div class=\"g-def\">정확한 버전·전체 트리 기록 → 재현성. <b>git 커밋 필수</b>. npm=package-lock.json, pnpm=pnpm-lock.yaml</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>frozen-lockfile</b><span>CI 설치</span></div><div class=\"g-def\"><code>pnpm install --frozen-lockfile</code> = npm의 <code>npm ci</code>. lock 불일치 시 설치 거부</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>npm → pnpm</b><span>command map</span></div><div class=\"g-def\"><code>install→install</code> · <code>install pkg→add pkg</code> · <code>uninstall→remove</code> · <code>run dev→dev</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>.nvmrc</b><span>nvm 버전</span></div><div class=\"g-def\">프로젝트 Node 버전 기록. nvm은 진입 시 <code>nvm use</code>를 <b>수동</b>으로 쳐야 적용</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>.mise.toml</b><span>mise 설정</span></div><div class=\"g-def\"><code>[tools]</code> 블록에 node·java 등 여러 런타임을 한 파일에 고정</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>mise use / install</b><span>버전 전환</span></div><div class=\"g-def\"><code>mise use node@22</code>(고정) · <code>mise install</code>(전부 설치) · <code>mise ls</code>(목록)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>mise activate</b><span>자동 전환</span></div><div class=\"g-def\"><code>eval \"$(mise activate zsh)\"</code>를 .zshrc에 → 디렉터리 진입 시 버전 자동 전환</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>packageManager 필드</b><span>팀 통일</span></div><div class=\"g-def\">package.json의 <code>\"packageManager\": \"pnpm@9\"</code> → corepack이 매니저를 강제</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">손에 먼저 붙일 것</span>\n<p>react/npm은 이미 익숙하니, 새로 익힐 건 셋입니다 — ① CI에선 <code>npm ci</code>(또는 <code>--frozen-lockfile</code>), ② 새 프로젝트는 pnpm, ③ Node·Java 버전은 mise + <code>.mise.toml</code> + activate로 자동 전환. \"라이브러리 설치\"와 \"런타임 버전\"이 다른 범주라는 감각 하나면 혼동의 90%가 사라집니다(→ Gradle 가이드와 함께 보면 JS·Java 양쪽 의존성/런타임 관리가 한 그림으로 맞춰집니다).</p>\n</div>\n</section>\n\n<footer>\nPACKAGE &amp; VERSION MANAGER GUIDE · V1 · 2026-06<br>\nSCOPE : npm · pnpm · yarn (패키지 매니저) · nvm · mise (런타임 버전 매니저)<br>\nENV : macOS · zsh · mise · chezmoi · COMPANION : GRADLE GUIDE (JVM 짝)\n</footer>\n\n<section id=\"doc-config\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>환경변수·설정</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : CONFIG-GUIDE-V1</span>\n    <span>SCOPE : PROPERTIES · PROFILES · ENV · SECRETS</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>환경변수·설정 관리<br>실무 가이드</h1>\n  <p class=\"hero-sub\">같은 빌드, 다른 환경 — 설정을 코드 밖으로 빼고 환경별로 분리하는 실무 가이드. <strong>Spring Boot 3.x</strong> 기준으로 application.yml·프로파일·환경변수 주입·시크릿 분리를 절차 중심으로 다룹니다. 프론트의 <code>.env</code>/<code>process.env</code> 감각이 있다면 그 대응을 짚어가며 읽으세요.</p>\n  <div class=\"hero-meta\">TARGET : Spring Boot 3.x · JDK 17+<br>NOTE : 프론트 .env 경험 → 백엔드 설정 모델로 매핑<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"config-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">CONFIG-01</span><h2>왜 설정을 외부화하나</h2></div>\n<p class=\"lede\">핵심 원칙 한 줄: <em>\"한 번 빌드한 아티팩트를, 환경마다 다른 설정으로 실행한다.\"</em> DB 주소·API 키가 코드에 박혀 있으면 환경이 바뀔 때마다 다시 빌드해야 합니다. 설정을 코드 밖으로 빼면 같은 <code>.jar</code> 하나로 local·staging·prod를 모두 돌립니다.</p>\n<p>이건 <a href=\"https://12factor.net\" style=\"color:var(--green)\">12-Factor App</a>의 3번 항목 \"Config\"입니다 — <em>코드와 설정을 엄격히 분리하라.</em> 판단 기준은 간단합니다: <strong>\"환경마다 달라지는 값인가?\"</strong> 달라지면 설정으로 빼고, 어디서나 같으면 코드에 둡니다. DB URL·비밀번호·외부 서비스 엔드포인트·기능 토글은 설정, 비즈니스 로직 상수는 코드입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">ANTI-PATTERN — 하드코딩</span>\n<span class=\"dim\">// 환경이 바뀌면 코드를 고치고 다시 빌드해야 함</span><br>\nString url = <span class=\"seg\">\"jdbc:postgresql://prod-db:5432/shop\"</span>;<br>\nString pw  = <span class=\"seg\">\"P@ssw0rd!\"</span>; <span class=\"dim\">// git에 비밀번호가 그대로 박힘</span><br>\n<br>\n<span class=\"sc-label\">PATTERN — 외부화</span>\n<span class=\"dim\"># application.yml — 값은 환경변수에서 주입</span><br>\nspring:<br>\n&nbsp;&nbsp;datasource:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;url: <span class=\"seg2\">${DB_URL}</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;password: <span class=\"seg2\">${DB_PASSWORD}</span>\n</div>\n<table>\n<tr><th>구분</th><th>코드에 둔다</th><th>설정으로 뺀다</th></tr>\n<tr><td>예시</td><td>세율 계산식, ENUM 값, 라우팅 규칙</td><td>DB URL·비번, API 키, 로그 레벨, 포트</td></tr>\n<tr><td>기준</td><td>모든 환경에서 동일</td><td>환경마다 달라짐</td></tr>\n<tr><td>바뀌면</td><td>재배포 정당</td><td>재빌드 없이 값만 교체</td></tr>\n</table>\n<div class=\"callout gm\">\n<span class=\"co-label\">프론트 대응</span>\n<p>프론트의 <code>process.env.NEXT_PUBLIC_API_URL</code>과 똑같은 발상입니다 — 빌드 산출물은 하나, 환경변수만 갈아끼웁니다. 다른 점: 프론트의 <code>NEXT_PUBLIC_*</code>는 <em>빌드 타임</em>에 번들에 박히지만, Spring Boot의 설정은 <em>런타임</em>에 읽힙니다. 그래서 백엔드는 같은 jar를 빌드 후 환경변수만 바꿔 재시작할 수 있습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"config-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">CONFIG-02</span><h2>application.yml vs application.properties</h2></div>\n<p class=\"lede\">Spring Boot는 <code>src/main/resources/</code>의 <code>application.properties</code> 또는 <code>application.yml</code>을 자동으로 읽습니다. 둘은 <em>같은 설정을 표현하는 두 문법</em>일 뿐 — properties는 점(<code>.</code>) 표기, yml은 들여쓰기 계층입니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">SAME CONFIG, TWO SYNTAXES</span>\n<span class=\"dim\"># application.properties — 점 표기, 한 줄 한 키</span><br>\nspring.datasource.url=<span class=\"seg\">jdbc:postgresql://localhost:5432/shop</span><br>\nspring.datasource.username=<span class=\"seg\">app</span><br>\nspring.jpa.hibernate.ddl-auto=<span class=\"seg\">validate</span><br>\n<br>\n<span class=\"dim\"># application.yml — 계층 들여쓰기, 공통 prefix를 묶음</span><br>\nspring:<br>\n&nbsp;&nbsp;datasource:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;url: <span class=\"seg\">jdbc:postgresql://localhost:5432/shop</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;username: <span class=\"seg\">app</span><br>\n&nbsp;&nbsp;jpa:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;hibernate:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;ddl-auto: <span class=\"seg\">validate</span>\n</div>\n<table>\n<tr><th>항목</th><th>properties</th><th>yml</th></tr>\n<tr><td>문법</td><td>점 표기 평면 키=값</td><td>들여쓰기 계층 (2칸, 탭 금지)</td></tr>\n<tr><td>중복 prefix</td><td>매 줄 반복 (<code>spring.datasource.*</code>)</td><td>한 번 묶어 재사용</td></tr>\n<tr><td>리스트·맵</td><td><code>list[0]=a</code> 인덱스 표기</td><td><code>- a</code> 네이티브 표현 (가독성↑)</td></tr>\n<tr><td>다중 문서</td><td>불가</td><td><code>---</code>로 프로파일 분리 가능</td></tr>\n<tr><td>주의</td><td>단순·견고</td><td>들여쓰기·탭에 민감, 값에 콜론 들어가면 인용 필요</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">yml 권장 이유</span>\n<p>설정이 깊고 많은 Spring Boot에서는 <strong>yml이 계층 구조를 그대로 보여줘</strong> 읽기 쉽습니다. 리스트·맵 표현도 자연스럽고, <code>---</code>로 한 파일에 프로파일별 설정을 나눠 담을 수 있습니다(→ CONFIG-03). 단점은 들여쓰기 민감성 — <strong>탭은 금지, 공백 2칸</strong>이 관례이고, 콜론·특수문자가 포함된 값은 <code>\"...\"</code>로 감쌉니다. 두 파일이 동시에 있으면 <code>.properties</code>가 같은 키를 이깁니다(→ CONFIG-05). 프로젝트에서 하나로 통일하세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"config-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">CONFIG-03</span><h2>프로파일로 환경 분리</h2></div>\n<p class=\"lede\">프로파일(profile)은 <em>\"이 설정 묶음을 어느 환경에서 쓸지\"</em> 이름표를 붙이는 메커니즘입니다. 공통은 <code>application.yml</code>에 두고, 환경별 차이만 <code>application-{profile}.yml</code>에 오버라이드합니다.</p>\n<div class=\"flow\">\n<span class=\"step\">application.yml<br>(공통)</span>\n<span class=\"arr\">+</span>\n<span class=\"step hl\">application-prod.yml<br>(prod 오버라이드)</span>\n<span class=\"arr\">=</span>\n<span class=\"step\">prod 실행 시<br>최종 설정</span>\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">FILE LAYOUT — src/main/resources/</span>\napplication.yml &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"dim\"># 모든 환경 공통 (항상 로드)</span><br>\napplication-<span class=\"seg\">local</span>.yml &nbsp;&nbsp;<span class=\"dim\"># 로컬 개발</span><br>\napplication-<span class=\"seg\">staging</span>.yml <span class=\"dim\"># 스테이징</span><br>\napplication-<span class=\"seg\">prod</span>.yml &nbsp;&nbsp;&nbsp;<span class=\"dim\"># 프로덕션</span><br>\n<br>\n<span class=\"sc-label\">ACTIVATE — 활성 프로파일 지정</span>\n<span class=\"dim\"># 1) 환경변수로 (운영 권장)</span><br>\nSPRING_PROFILES_ACTIVE=<span class=\"seg\">prod</span> java -jar app.jar<br>\n<span class=\"dim\"># 2) 커맨드라인 인자로</span><br>\njava -jar app.jar --spring.profiles.active=<span class=\"seg\">prod</span>\n</div>\n<p>활성 프로파일을 <code>prod</code>로 지정하면 Spring Boot는 <code>application.yml</code>(공통)을 먼저 읽고, 그 위에 <code>application-prod.yml</code>을 <strong>덮어씁니다.</strong> 공통에 둔 값은 그대로 살고, prod 파일에 같은 키가 있으면 그게 이깁니다. 활성 프로파일이 없으면 <code>application.yml</code>만 적용됩니다(이것이 사실상의 <code>default</code>).</p>\n<table>\n<tr><th>설정</th><th>application.yml (공통)</th><th>application-prod.yml</th><th>prod 최종</th></tr>\n<tr><td><code>logging.level.root</code></td><td>INFO</td><td>WARN</td><td>WARN (오버라이드)</td></tr>\n<tr><td><code>server.port</code></td><td>8080</td><td>(없음)</td><td>8080 (공통 유지)</td></tr>\n<tr><td><code>jpa.show-sql</code></td><td>true</td><td>false</td><td>false (오버라이드)</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">프로파일 활성화는 환경변수로</span>\n<p><code>application.yml</code> 안에 <code>spring.profiles.active: prod</code>를 박지 마세요 — 그러면 어느 환경에서 띄워도 prod가 됩니다. 활성 프로파일은 <strong>실행 환경(환경변수 <code>SPRING_PROFILES_ACTIVE</code> 또는 커맨드라인 인자)에서 주입</strong>하는 게 원칙입니다. 여러 개를 동시에 켜려면 쉼표로: <code>SPRING_PROFILES_ACTIVE=prod,metrics</code>. 한 yml 파일 안에서 <code>---</code>와 <code>spring.config.activate.on-profile</code>로 문서를 나눠 담는 방식도 있습니다(Boot 3.x 문법, 구버전 <code>spring.profiles</code>는 deprecated).</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"config-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">CONFIG-04</span><h2>환경변수 주입</h2></div>\n<p class=\"lede\">운영에서 값을 넣는 가장 흔한 통로는 환경변수입니다. Spring Boot는 <em>relaxed binding</em> 덕분에 OS 환경변수의 대문자·언더스코어 표기를 점 표기 프로퍼티로 알아서 매핑합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">RELAXED BINDING — 환경변수 → 프로퍼티</span>\n<span class=\"seg\">SPRING_DATASOURCE_URL</span> &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;→ &nbsp;spring.datasource.url<br>\n<span class=\"seg\">SPRING_DATASOURCE_PASSWORD</span> &nbsp;→ &nbsp;spring.datasource.password<br>\n<span class=\"seg\">SERVER_PORT</span> &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;→ &nbsp;server.port<br>\n<span class=\"dim\"># 규칙: 점(.)·대시(-) → 언더스코어(_), 전부 대문자</span><br>\n<br>\n<span class=\"sc-label\">PLACEHOLDER — yml 안에서 환경변수 참조 + 기본값</span>\nspring:<br>\n&nbsp;&nbsp;datasource:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;url: <span class=\"seg2\">${DB_URL:jdbc:postgresql://localhost:5432/shop}</span><br>\n<span class=\"dim\">&nbsp;&nbsp;&nbsp;&nbsp;#     ${변수명:기본값} — 변수 없으면 콜론 뒤 기본값 사용</span>\n</div>\n<p>두 가지 방식이 있습니다. <strong>① relaxed binding</strong>은 yml에 안 적어도 <code>SPRING_DATASOURCE_URL</code> 환경변수만 있으면 <code>spring.datasource.url</code>로 바인딩됩니다 — Spring이 정의한 프로퍼티에 직접 꽂는 방식. <strong>② placeholder <code>${...}</code></strong>는 yml 안에서 명시적으로 환경변수를 참조하고 <code>:기본값</code>으로 fallback을 줍니다 — 커스텀 프로퍼티나 기본값이 필요할 때.</p>\n<table>\n<tr><th>방식</th><th>표기</th><th>언제</th></tr>\n<tr><td>relaxed binding</td><td>OS env <code>SPRING_DATASOURCE_URL</code></td><td>Spring 표준 프로퍼티 오버라이드. yml 수정 불필요</td></tr>\n<tr><td>placeholder</td><td>yml에 <code>${DB_URL}</code></td><td>커스텀 키, 기본값 fallback이 필요할 때</td></tr>\n<tr><td>placeholder + default</td><td><code>${DB_URL:기본값}</code></td><td>로컬은 기본값, 운영은 env로 덮기</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">기본값 fallback의 함정</span>\n<p><code>${DB_PASSWORD:changeme}</code>처럼 <strong>비밀번호에 기본값을 주면</strong> 환경변수 주입을 깜빡해도 앱이 그 기본값으로 떠버립니다 — 운영에서 위험합니다. DB URL·로그 레벨처럼 누락돼도 안전한 값엔 기본값을 주되, 시크릿엔 주지 마세요. 시크릿이 누락되면 차라리 앱이 부팅에 실패하는 게 낫습니다. 또 placeholder가 없는 환경변수를 <code>:</code> 없이 <code>${DB_URL}</code>로 참조하면 기동 시 에러가 납니다 — 의도적 가드로 쓸 수 있습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"config-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">CONFIG-05</span><h2>설정 우선순위 — 누가 누구를 이기나</h2></div>\n<p class=\"lede\">같은 키가 여러 곳에 있으면 누가 이길까. 핵심 원칙: <em>\"바깥에서 주입한 것이 안에 박힌 것을 이긴다.\"</em> 커맨드라인 인자가 가장 세고, jar 안의 <code>application.yml</code>이 가장 약합니다.</p>\n<div class=\"flow\">\n<span class=\"step hl\">커맨드라인 인자</span>\n<span class=\"arr\">&gt;</span>\n<span class=\"step\">OS 환경변수</span>\n<span class=\"arr\">&gt;</span>\n<span class=\"step\">application-{profile}</span>\n<span class=\"arr\">&gt;</span>\n<span class=\"step\">application (공통)</span>\n</div>\n<p>위는 실무에서 자주 부딪치는 핵심 구간만 추린 것입니다. Spring Boot의 실제 우선순위 체계는 더 길지만(테스트 프로퍼티, <code>SPRING_APPLICATION_JSON</code>, Java 시스템 프로퍼티 등 포함), 일상에서 기억할 규칙은 <strong>\"더 바깥·더 구체적인 것이 이긴다\"</strong> 하나입니다.</p>\n<table>\n<tr><th>우선순위</th><th>출처</th><th>예시</th></tr>\n<tr><td>높음 (이김)</td><td>커맨드라인 인자</td><td><code>--server.port=9090</code></td></tr>\n<tr><td>↑</td><td>OS 환경변수</td><td><code>SERVER_PORT=9090</code></td></tr>\n<tr><td>↑</td><td>Java 시스템 프로퍼티</td><td><code>-Dserver.port=9090</code></td></tr>\n<tr><td>↓</td><td>application-{profile}.yml</td><td>프로파일별 오버라이드</td></tr>\n<tr><td>낮음 (짐)</td><td>application.yml (공통)</td><td>기본값 묶음</td></tr>\n</table>\n<p>같은 레벨 안에서는 <strong>프로파일별 파일이 공통 파일을 이깁니다</strong> — <code>application-prod.yml</code>의 <code>server.port</code>가 <code>application.yml</code>의 <code>server.port</code>를 덮습니다. 그리고 jar <em>바깥</em>(실행 디렉터리)에 둔 <code>application.yml</code>이 jar <em>안</em>에 패키징된 것을 이깁니다 — 빌드 안 하고 운영 설정을 바꾸는 방법.</p>\n<div class=\"callout gm\">\n<span class=\"co-label\">실무 동선</span>\n<p>이 우선순위 덕분에 한 가지 패턴이 가능합니다 — <strong>합리적 기본값은 <code>application.yml</code>에, 환경별 차이는 프로파일 파일에, 시크릿·환경 의존 값은 환경변수로, 일회성 디버깅 오버라이드는 커맨드라인 인자로.</strong> 디버깅 중 \"이 값만 잠깐 바꿔서 띄워보자\"는 <code>--logging.level.root=DEBUG</code> 한 줄이면 됩니다 — 파일을 안 건드리고, 그 실행에만 적용됩니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"config-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">CONFIG-06</span><h2>코드에서 설정 읽기</h2></div>\n<p class=\"lede\">주입한 설정을 자바 코드에서 꺼내는 길은 둘입니다 — 값 하나를 콕 집는 <code>@Value</code>, 관련 설정을 묶어 타입 안전하게 바인딩하는 <code>@ConfigurationProperties</code>.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">@Value — 단일 값 주입</span>\n<span class=\"seg2\">@Component</span><br>\n<span class=\"dim\">public class</span> MailSender {<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Value(</span><span class=\"seg\">\"${app.mail.from:noreply@greenery.io}\"</span><span class=\"seg2\">)</span><br>\n&nbsp;&nbsp;<span class=\"dim\">private</span> String from; <span class=\"dim\">// 기본값 fallback 포함</span><br>\n}<br>\n<br>\n<span class=\"sc-label\">@ConfigurationProperties — 묶음 바인딩 (record, Boot 3.x)</span>\n<span class=\"seg2\">@ConfigurationProperties(prefix = </span><span class=\"seg\">\"app.mail\"</span><span class=\"seg2\">)</span><br>\n<span class=\"dim\">public record</span> MailProperties(<br>\n&nbsp;&nbsp;String from,<br>\n&nbsp;&nbsp;String host,<br>\n&nbsp;&nbsp;<span class=\"dim\">int</span> port<br>\n) {}<br>\n<span class=\"dim\"># 매핑되는 yml:  app.mail.from / app.mail.host / app.mail.port</span>\n</div>\n<p><code>@ConfigurationProperties</code>를 쓰려면 메인 클래스나 <code>@Configuration</code>에 <code>@ConfigurationPropertiesScan</code>(또는 <code>@EnableConfigurationProperties(MailProperties.class)</code>)을 붙여 빈으로 등록합니다. record로 선언하면 불변(immutable) 바인딩이 되고, 생성자 바인딩이라 누락·타입 불일치를 기동 시점에 잡습니다.</p>\n<table>\n<tr><th>기준</th><th>@Value</th><th>@ConfigurationProperties</th></tr>\n<tr><td>대상</td><td>값 하나</td><td>prefix로 묶인 여러 값</td></tr>\n<tr><td>타입 안전</td><td>문자열 기반, 약함</td><td>record/class로 강함</td></tr>\n<tr><td>기본값</td><td><code>${x:default}</code> 인라인</td><td>필드 기본값 / 검증</td></tr>\n<tr><td>검증</td><td>어려움</td><td><code>@Validated</code> + Bean Validation 가능</td></tr>\n<tr><td>relaxed binding</td><td>제한적</td><td>완전 지원</td></tr>\n<tr><td>언제</td><td>값 한두 개 급할 때</td><td>관련 설정 묶음 (권장 기본)</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">어느 걸 언제</span>\n<p>설정이 두 개 이상 한 도메인으로 묶이면 <strong><code>@ConfigurationProperties</code> + record가 기본</strong>입니다 — 타입 안전하고, IDE 자동완성이 되고(<code>spring-boot-configuration-processor</code> 의존성 추가 시), 검증을 붙일 수 있고, 테스트하기 쉽습니다. <code>@Value</code>는 정말 값 하나를 급히 꽂을 때만. 프론트로 치면 <code>@Value</code>는 <code>process.env.X</code>를 곳곳에서 직접 읽는 것, <code>@ConfigurationProperties</code>는 설정을 한 객체로 모아 타입 붙여 쓰는 config 모듈 패턴에 가깝습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"config-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">CONFIG-07</span><h2>시크릿 분리</h2></div>\n<p class=\"lede\">비밀번호·API 키·토큰은 설정 중에서도 특별 취급입니다. 원칙 하나만 절대 지키세요 — <em>시크릿은 코드와 git에 절대 들어가지 않는다.</em></p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">NEVER — git에 들어가면 안 되는 것</span>\n<span class=\"seg\">spring.datasource.password=P@ssw0rd!</span> <span class=\"dim\"># ✗ yml에 평문</span><br>\n<span class=\"seg\">API_KEY = \"sk-live-abc123\"</span> &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"dim\"># ✗ 코드에 박힘</span><br>\n<br>\n<span class=\"sc-label\">INSTEAD — 환경변수 / secret manager로 주입</span>\nspring:<br>\n&nbsp;&nbsp;datasource:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;password: <span class=\"seg2\">${DB_PASSWORD}</span> <span class=\"dim\"># 값은 런타임 주입, 기본값 없음</span><br>\n<br>\n<span class=\"sc-label\">.gitignore — 로컬 시크릿 파일 차단</span>\n.env<br>\napplication-local.yml <span class=\"dim\"># 개인 시크릿이 들어간다면</span><br>\n*.pem\n</div>\n<p>시크릿을 주입하는 길은 환경에 따라 다릅니다. <strong>로컬</strong>은 <code>.env</code> 파일(+ <code>.gitignore</code>)이나 IDE run config. <strong>운영</strong>은 환경변수, 또는 AWS Secrets Manager·HashiCorp Vault·Kubernetes Secret 같은 secret manager. 공통점은 값이 코드 저장소를 거치지 않는다는 것입니다.</p>\n<table>\n<tr><th>환경</th><th>시크릿 주입 방법</th></tr>\n<tr><td>로컬 개발</td><td><code>.env</code> (+.gitignore) / IDE run config 환경변수</td></tr>\n<tr><td>CI</td><td>CI 시크릿 저장소 (GitHub Actions Secrets 등)</td></tr>\n<tr><td>운영</td><td>환경변수 / Secrets Manager / Vault / K8s Secret</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">유출되면 — 지우지 말고 rotate</span>\n<p>시크릿을 실수로 커밋했다면, <strong>git 히스토리에서 지우는 것만으로는 끝나지 않습니다</strong> — 이미 push됐다면 누군가 봤다고 가정하고 <strong>즉시 그 키·비밀번호를 폐기(rotate)</strong>하세요. 새 값을 발급하고 옛 값을 무효화하는 게 우선이고, 히스토리 정리는 그다음입니다. 노출된 시크릿은 봇이 분 단위로 스캔합니다. 예방: 커밋 전 <code>git-secrets</code>·<code>gitleaks</code> 같은 스캐너를 pre-commit hook으로 걸어두면 사고 자체를 막습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"config-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">CONFIG-08</span><h2>로컬 개발 설정</h2></div>\n<p class=\"lede\">팀이 공유하는 설정과 개인 머신에만 있는 값을 구분하는 게 핵심입니다 — 공유 설정은 git에, 개인 시크릿·취향은 git 밖에.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">SHARED — git에 커밋 (팀 공통 로컬 설정)</span>\n<span class=\"dim\"># application-local.yml — 로컬 공통 기본값</span><br>\nspring:<br>\n&nbsp;&nbsp;datasource:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;url: <span class=\"seg2\">${DB_URL:jdbc:postgresql://localhost:5432/shop}</span><br>\n&nbsp;&nbsp;jpa:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;show-sql: <span class=\"seg\">true</span> <span class=\"dim\"># 로컬에선 SQL 보기</span><br>\n<br>\n<span class=\"sc-label\">PERSONAL — git에서 제외 (.gitignore)</span>\n<span class=\"dim\"># .env — 개인 시크릿·머신별 값</span><br>\nDB_PASSWORD=<span class=\"seg\">my-local-pw</span><br>\nSPRING_PROFILES_ACTIVE=<span class=\"seg\">local</span>\n</div>\n<p>실무 동선은 보통 이렇습니다. ① <code>application-local.yml</code>에 로컬 공통 기본값을 두고 <strong>git에 커밋</strong>(시크릿은 placeholder로). ② 개인 시크릿·머신별 차이는 <code>.env</code>에 두고 <strong><code>.gitignore</code>로 제외.</strong> ③ IDE에서는 run configuration의 환경변수란에 <code>SPRING_PROFILES_ACTIVE=local</code>과 시크릿을 넣습니다 — IntelliJ는 <code>.env</code>를 자동으로 읽지 않으므로 EnvFile 플러그인을 쓰거나 run config에 직접 넣습니다.</p>\n<table>\n<tr><th>대상</th><th>위치</th><th>git</th></tr>\n<tr><td>로컬 공통 기본값</td><td><code>application-local.yml</code></td><td>커밋</td></tr>\n<tr><td>개인 시크릿·머신별 값</td><td><code>.env</code> / IDE run config</td><td>제외</td></tr>\n<tr><td>예시 템플릿</td><td><code>.env.example</code></td><td>커밋 (키만, 값은 빈칸)</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">팀 온보딩을 위한 .env.example</span>\n<p><code>.env</code>는 git에서 빼지만, <strong>키 목록만 담은 <code>.env.example</code>은 커밋</strong>하세요 — 새 팀원이 \"무슨 환경변수를 채워야 하는지\" 한눈에 압니다. 프론트의 <code>.env.local</code> / <code>.env.example</code> 관례와 정확히 같습니다. 값은 비우거나 더미를 넣고, 실제 값은 각자 채웁니다. README에 \"어디서 그 값을 받는지\"(예: 1Password vault, 팀 리드 문의)를 한 줄 적어두면 온보딩이 매끄럽습니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 9 ============ -->\n<section id=\"config-ch9\">\n<div class=\"ch-head\"><span class=\"ch-code\">CONFIG-09</span><h2>치트시트</h2></div>\n<p class=\"lede\">자주 헷갈리는 규칙과 표기를 한 곳에. 외우기보다 \"이런 게 있다\"를 알아두고 필요할 때 찾으세요.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>설정 외부화</b><span>externalized config</span></div><div class=\"g-def\">환경마다 달라지는 값을 코드 밖으로. 같은 아티팩트를 환경별 설정으로 실행 — 12-Factor \"Config\"</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>application.yml</b><span>계층 들여쓰기</span></div><div class=\"g-def\">공백 2칸 들여쓰기, 탭 금지. 깊은 설정에 권장. <code>---</code>로 다중 문서 가능</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>application.properties</b><span>점 표기</span></div><div class=\"g-def\"><code>spring.datasource.url=...</code> 평면 키=값. 단순하고 견고. 같은 키면 yml을 이김</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>프로파일</b><span>profile</span></div><div class=\"g-def\"><code>application-{profile}.yml</code>. 공통(application.yml) + 프로파일 오버라이드. local/staging/prod</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>활성 프로파일</b><span>active profile</span></div><div class=\"g-def\"><code>SPRING_PROFILES_ACTIVE=prod</code> 또는 <code>--spring.profiles.active=prod</code>. 실행 환경에서 주입</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>relaxed binding</b><span>env → property</span></div><div class=\"g-def\"><code>SPRING_DATASOURCE_URL</code> → <code>spring.datasource.url</code>. 점·대시→언더스코어, 대문자</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>placeholder</b><span>${...}</span></div><div class=\"g-def\"><code>${DB_URL}</code> 환경변수 참조. <code>${DB_URL:기본값}</code> 콜론 뒤 fallback. 시크릿엔 기본값 금지</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>우선순위</b><span>precedence</span></div><div class=\"g-def\">커맨드라인 인자 &gt; 환경변수 &gt; application-{profile} &gt; application. 바깥·구체적인 게 이김</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>@Value</b><span>단일 값</span></div><div class=\"g-def\"><code>@Value(\"${app.x:기본값}\")</code>. 값 하나 급할 때만. 타입 안전 약함</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>@ConfigurationProperties</b><span>묶음 바인딩</span></div><div class=\"g-def\"><code>prefix</code>로 record/class에 타입 안전 바인딩. 묶인 설정의 기본 선택. 검증 가능</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>시크릿 분리</b><span>secrets</span></div><div class=\"g-def\">코드·git 절대 금지. 환경변수/secret manager로 주입. 로컬은 <code>.env</code>+<code>.gitignore</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>유출 대응</b><span>rotate</span></div><div class=\"g-def\">커밋됐으면 히스토리 삭제로 끝나지 않음 — 즉시 키·비번 rotate. 봇이 분 단위로 스캔함</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>.env.example</b><span>온보딩 템플릿</span></div><div class=\"g-def\">키 목록만 커밋(값은 빈칸). 새 팀원이 채울 환경변수를 한눈에 파악</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>jar 바깥 설정</b><span>external file</span></div><div class=\"g-def\">실행 디렉터리의 <code>application.yml</code>이 jar 안 것을 이김 — 재빌드 없이 운영 설정 교체</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">손에 먼저 붙일 것</span>\n<p>전부 외우려 하지 마세요. 핵심 동선: <strong>① 공통은 <code>application.yml</code>, 환경 차이는 프로파일 파일 ② 시크릿·환경 의존 값은 환경변수(<code>${...}</code>)로 ③ 코드에선 <code>@ConfigurationProperties</code> record로 묶어 읽기 ④ 시크릿은 git 밖, 유출되면 rotate.</strong> 이 네 가지가 일상의 대부분입니다. 우선순위는 \"바깥이 안을 이긴다\" 한 줄로 기억하면, 디버깅 중 커맨드라인 인자로 잠깐 덮어보는 기술이 자연스럽게 따라옵니다.</p>\n</div>\n</section>\n\n<footer>\nENVIRONMENT &amp; CONFIG MANAGEMENT GUIDE · V1 · 2026-06<br>\nTARGET : Spring Boot 3.x · JDK 17+ · SCOPE : PROPERTIES · PROFILES · ENV · SECRETS<br>\nNOTE : 프론트 .env/process.env 경험을 백엔드 설정 모델로 매핑 · PRINCIPLE : 같은 빌드, 다른 설정\n</footer>\n\n<section id=\"doc-dbseed\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>DB 스키마·시딩</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : SEED-GUIDE-V1</span>\n    <span>SCOPE : DDL · MIGRATION · SEED</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>DB 스키마·로컬 시딩<br>실무 가이드</h1>\n  <p class=\"hero-sub\">스키마를 안전하게 관리하고 로컬 데이터를 자동 복구하는 실무 가이드. \"실제로 어떻게 하나\"에 초점을 둡니다 — 누가 스키마를 소유하는지, 마이그레이션을 어떻게 쌓는지, 로컬 DB를 날려도 한 번의 재구동으로 복구되게 만드는 법까지. Spring Boot · JPA · Flyway · PostgreSQL 기준.</p>\n  <div class=\"hero-meta\">STACK : Spring Boot · JPA(Hibernate) · Flyway · PostgreSQL<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"dbseed-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEED-01</span><h2>스키마는 누가 관리하나</h2></div>\n<p class=\"lede\">먼저 결정할 한 가지: <em>테이블 구조의 단일 진실원천(source of truth)은 무엇인가.</em> JPA 엔티티가 자동으로 테이블을 만들게 둘 것인가, 아니면 사람이 쓴 SQL 마이그레이션이 정본인가. 정답은 후자입니다. 이유부터 봅니다.</p>\n<p>Spring Boot에서 Hibernate의 <code>spring.jpa.hibernate.ddl-auto</code> 설정은 애플리케이션이 뜰 때 엔티티를 보고 DDL을 어떻게 처리할지 결정합니다. 편해 보이지만 운영에서는 위험합니다 — 엔티티 변경이 곧 <em>예측 불가능한 ALTER</em>로 번역되기 때문입니다.</p>\n<table>\n<tr><th>ddl-auto</th><th>동작</th><th>위험성 / 용도</th></tr>\n<tr><td><code>none</code></td><td>아무것도 안 함</td><td>가장 안전. 스키마는 Flyway가 전담. <b>운영 권장</b></td></tr>\n<tr><td><code>validate</code></td><td>엔티티와 실제 테이블이 맞는지 검증만, 불일치면 기동 실패</td><td>변경은 안 하되 어긋남을 잡아줌. <b>운영 권장</b></td></tr>\n<tr><td><code>update</code></td><td>차이를 감지해 <code>ALTER</code>로 맞춤</td><td>컬럼 삭제·타입 변경을 못 하고, 적용 순서·결과가 불투명. <b>운영 절대 금지</b></td></tr>\n<tr><td><code>create</code></td><td>기동 때 테이블을 <code>DROP</code> 후 재생성</td><td>기존 데이터 전부 소실. 일회성 실험용</td></tr>\n<tr><td><code>create-drop</code></td><td>기동 때 생성, 종료 때 <code>DROP</code></td><td>데이터 휘발. 단발 테스트 외 금지</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">RECOMMENDED — application.yml (운영/공통)</span>\nspring:<br>\n&nbsp;&nbsp;jpa:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;hibernate:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;ddl-auto: <span class=\"seg\">validate</span>&nbsp;&nbsp;<span class=\"dim\"># 엔티티 ↔ 실제 스키마 불일치를 기동 시점에 잡음</span><br>\n&nbsp;&nbsp;flyway:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;enabled: <span class=\"seg2\">true</span>&nbsp;&nbsp;<span class=\"dim\"># 스키마의 단일 진실원천은 Flyway 마이그레이션</span>\n</div>\n<div class=\"callout risk\">\n<span class=\"co-label\">운영에서 update 금지</span>\n<p><code>update</code>는 <em>컬럼 삭제, 타입 축소, 제약 변경을 수행하지 못합니다</em> — 더하기만 가능하고, 그나마도 DB 벤더·Hibernate 버전에 따라 결과가 달라집니다. \"로컬에선 잘 되던 게 운영에서 ALTER가 다르게 나가는\" 사고의 단골입니다. 스키마 변경은 <strong>버전 매겨진 SQL 마이그레이션</strong>으로만. 엔티티는 <code>validate</code>로 \"내가 아는 구조와 실제가 같은가\"만 확인하게 두세요.</p>\n</div>\n<p>정리하면 <strong>스키마의 주인은 마이그레이션 도구</strong>이고, JPA는 그 결과를 읽어 매핑하는 소비자입니다. 다음 장에서 그 도구를 봅니다.</p>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"dbseed-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEED-02</span><h2>마이그레이션 도구 — Flyway</h2></div>\n<p class=\"lede\">Flyway는 <em>버전 매겨진 SQL 파일을 순서대로, 한 번씩만</em> 적용하고 그 이력을 DB에 기록합니다. \"지금 이 DB가 몇 번 버전까지 와 있는가\"를 도구가 알기 때문에, 어떤 환경에서 시작하든 같은 최종 스키마에 도달합니다.</p>\n<h3><span class=\"h3-tag\">2.1</span>의존성</h3>\n<p>Spring Boot는 클래스패스에 Flyway가 있으면 기동 때 자동으로 마이그레이션을 돌립니다(<code>spring.flyway.enabled=true</code>가 기본). PostgreSQL은 별도 모듈이 필요합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">build.gradle (Gradle · Kotlin DSL이면 괄호 표기로)</span>\nimplementation <span class=\"seg2\">'org.flywaydb:flyway-core'</span><br>\nimplementation <span class=\"seg2\">'org.flywaydb:flyway-database-postgresql'</span>&nbsp;&nbsp;<span class=\"dim\"># Flyway 10+ PostgreSQL 지원 모듈</span><br>\n<span class=\"dim\"># 버전은 Spring Boot BOM이 관리 → 명시 불필요</span>\n</div>\n<h3><span class=\"h3-tag\">2.2</span>위치와 네이밍 규칙</h3>\n<p>마이그레이션 파일은 <code>src/main/resources/db/migration</code>에 둡니다. 파일명이 곧 메타데이터라 규칙이 엄격합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">FILE NAMING — V&lt;버전&gt;__&lt;설명&gt;.sql</span>\n<span class=\"seg\">V</span>1<span class=\"seg2\">__</span>init_emission_schema.sql&nbsp;&nbsp;<span class=\"dim\"># V + 버전 + 언더스코어 2개 + 설명</span><br>\n<span class=\"seg\">V</span>2<span class=\"seg2\">__</span>add_credit_status_column.sql<br>\n<span class=\"seg\">V</span>2.1<span class=\"seg2\">__</span>backfill_credit_status.sql&nbsp;&nbsp;<span class=\"dim\"># 점 표기로 세부 버전도 가능</span><br>\n<span class=\"seg\">R</span><span class=\"seg2\">__</span>seed_reference_data.sql&nbsp;&nbsp;<span class=\"dim\"># R = repeatable, 체크섬 바뀌면 매번 재적용(→ SEED-04)</span>\n</div>\n<table>\n<tr><th>요소</th><th>규칙</th></tr>\n<tr><td>접두 <code>V</code></td><td>versioned 마이그레이션. 한 번만 적용되고 순서대로 진행</td></tr>\n<tr><td>버전 번호</td><td><code>1</code>, <code>2</code>, <code>2.1</code> 등. 정렬 순서가 곧 적용 순서</td></tr>\n<tr><td>구분자 <code>__</code></td><td><b>언더스코어 두 개</b> — 버전과 설명을 가름. 하나면 인식 안 됨</td></tr>\n<tr><td>설명</td><td>단어는 <code>_</code>로 연결. 사람이 읽는 용도</td></tr>\n</table>\n<h3><span class=\"h3-tag\">2.3</span>적용 순서와 이력 테이블</h3>\n<p>Flyway는 처음 돌 때 <code>flyway_schema_history</code> 테이블을 만들고, 적용한 스크립트마다 버전·체크섬·실행시각·성공여부를 한 행씩 기록합니다. 다음 기동 때는 이 표를 읽어 <em>아직 적용 안 된 버전만</em> 순서대로 실행합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">flyway_schema_history (개념 — 일부 컬럼)</span>\n<span class=\"dim\">installed_rank | version | description     | checksum   | success</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;1&nbsp;&nbsp;&nbsp;&nbsp;|&nbsp;&nbsp; 1&nbsp;&nbsp;&nbsp;| init_emission   | <span class=\"seg2\">-1740…</span> |&nbsp;&nbsp;<span class=\"seg\">t</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;2&nbsp;&nbsp;&nbsp;&nbsp;|&nbsp;&nbsp; 2&nbsp;&nbsp;&nbsp;| add_credit_…    | <span class=\"seg2\">&nbsp;913…</span> |&nbsp;&nbsp;<span class=\"seg\">t</span>\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">불변 원칙 — 적용된 스크립트는 고치지 않는다</span>\n<p>한 번 적용돼 이력에 기록된 <code>V</code> 파일은 <em>절대 내용을 바꾸지 않습니다.</em> Flyway는 기동 때 파일 내용의 체크섬을 다시 계산해 이력의 값과 대조하는데, 다르면 <code>Migration checksum mismatch</code>로 기동을 막습니다. 이미 적용된 마이그레이션을 수정하면 다른 환경(동료 로컬·운영)에서 충돌이 터집니다. <strong>변경이 필요하면 기존 파일을 고치지 말고 새 <code>V</code> 파일을 추가</strong>하세요. 잘못 머지된 파일을 정리할 때만 <code>flyway repair</code>로 체크섬을 재기록합니다 — 평소엔 쓸 일이 없어야 정상입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"dbseed-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEED-03</span><h2>마이그레이션 작성 패턴</h2></div>\n<p class=\"lede\">마이그레이션은 결국 SQL입니다. 자주 쓰는 형태 몇 개와, 운영에서 다운타임 없이 바꾸는 사고법(expand-contract)을 봅니다.</p>\n<h3><span class=\"h3-tag\">3.1</span>기본 DDL</h3>\n<div class=\"serial-card\">\n<span class=\"sc-label\">V2__add_credit_status_column.sql</span>\n<span class=\"dim\">-- 컬럼 추가: 운영 데이터가 있으면 NOT NULL은 기본값과 함께</span><br>\nALTER TABLE credit<br>\n&nbsp;&nbsp;ADD COLUMN status VARCHAR(20) NOT NULL DEFAULT <span class=\"seg2\">'PENDING'</span>;<br>\n<br>\n<span class=\"dim\">-- 조회 패턴에 맞는 인덱스. CONCURRENTLY는 락을 덜 잡음(아래 주의)</span><br>\nCREATE INDEX idx_credit_status ON credit (status);<br>\n<br>\n<span class=\"dim\">-- 제약 추가: FK로 무결성 보장</span><br>\nALTER TABLE credit<br>\n&nbsp;&nbsp;ADD CONSTRAINT fk_credit_project<br>\n&nbsp;&nbsp;FOREIGN KEY (project_id) REFERENCES project (id);\n</div>\n<table>\n<tr><th>변경</th><th>핵심 / 왜</th></tr>\n<tr><td>컬럼 추가</td><td>운영 테이블에 <code>NOT NULL</code>을 그냥 붙이면 기존 행 때문에 실패 → <code>DEFAULT</code>를 함께</td></tr>\n<tr><td>인덱스</td><td>WHERE·JOIN·ORDER BY에 쓰이는 컬럼에. 없으면 풀스캔, 과하면 쓰기 비용</td></tr>\n<tr><td>제약(FK·UNIQUE)</td><td>데이터 무결성을 DB가 강제 — 애플리케이션 버그가 더러운 데이터로 굳는 걸 막음</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">PostgreSQL — 인덱스와 락</span>\n<p>큰 운영 테이블에 그냥 <code>CREATE INDEX</code>를 걸면 그동안 쓰기가 막힙니다. <code>CREATE INDEX CONCURRENTLY</code>는 락을 거의 안 잡지만 <em>트랜잭션 안에서 실행할 수 없습니다.</em> Flyway는 마이그레이션을 기본적으로 트랜잭션으로 감싸므로, 해당 스크립트 상단에 <code>-- flyway:executeInTransaction=false</code>를 두거나 그 마이그레이션을 분리해야 합니다.</p>\n</div>\n<h3><span class=\"h3-tag\">3.2</span>무중단 변경 — expand-contract</h3>\n<p>컬럼 이름 변경, 타입 변경처럼 \"구버전 앱과 신버전 앱이 잠깐 함께 도는\" 배포에서 한 방에 바꾸면 한쪽이 깨집니다. <em>확장(expand) → 이행 → 수축(contract)</em>으로 단계를 나눕니다.</p>\n<div class=\"flow\">\n<span class=\"step hl\">1 · EXPAND</span><span class=\"arr\">→</span>\n<span class=\"step\">2 · 양쪽 쓰기</span><span class=\"arr\">→</span>\n<span class=\"step\">3 · 백필</span><span class=\"arr\">→</span>\n<span class=\"step\">4 · 읽기 전환</span><span class=\"arr\">→</span>\n<span class=\"step hl\">5 · CONTRACT</span>\n</div>\n<table>\n<tr><th>단계</th><th>하는 일 / 왜</th></tr>\n<tr><td>1 EXPAND</td><td>새 컬럼을 nullable로 추가. 구버전 앱은 모르고도 정상 동작</td></tr>\n<tr><td>2 양쪽 쓰기</td><td>신버전 앱이 옛 컬럼·새 컬럼에 동시에 기록 — 어느 쪽을 읽어도 일관</td></tr>\n<tr><td>3 백필</td><td>기존 행의 새 컬럼을 채우는 마이그레이션 실행</td></tr>\n<tr><td>4 읽기 전환</td><td>새 컬럼을 읽도록 배포. 모든 인스턴스가 신버전이 된 뒤</td></tr>\n<tr><td>5 CONTRACT</td><td>옛 컬럼 삭제·제약 강화(<code>NOT NULL</code>). <b>되돌아갈 필요가 없어진 뒤</b></td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">핵심 — 한 마이그레이션 = 안전한 한 걸음</span>\n<p>각 단계가 별도 배포·별도 <code>V</code> 파일입니다. \"옛 컬럼 삭제\"는 새 코드가 완전히 깔리고 롤백 가능성이 사라진 다음에야 합니다. 한 PR에서 컬럼을 추가하고 같은 PR에서 옛 컬럼을 지우면 expand-contract가 아니라 그냥 위험한 한 방입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"dbseed-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEED-04</span><h2>로컬 시딩 방법 비교</h2></div>\n<p class=\"lede\">시딩은 \"스키마(빈 테이블)에 개발용 데이터를 채우는\" 일입니다. 마이그레이션과는 목적이 다릅니다 — 마이그레이션은 <em>구조</em>, 시딩은 <em>샘플 데이터</em>. Spring 생태계에서 흔한 세 방법을 비교합니다.</p>\n<table>\n<tr><th>방법</th><th>동작</th><th>장점 / 단점</th></tr>\n<tr><td><code>data.sql</code></td><td><code>src/main/resources/data.sql</code>을 기동 때 실행</td><td>가장 간단. 단, 멱등성 없음 → 재실행 시 중복·PK 충돌. 로직 불가</td></tr>\n<tr><td>시더 컴포넌트<br>(<code>CommandLineRunner</code>·<code>ApplicationRunner</code>)</td><td>기동 후 Java 코드로 데이터 삽입</td><td>조건 분기·멱등 처리 가능, Repository 재사용. 코드를 직접 써야 함</td></tr>\n<tr><td>Flyway <code>R__seed.sql</code></td><td>repeatable 마이그레이션으로 시드 SQL</td><td>마이그레이션 파이프라인에 통합, 체크섬 바뀌면 재적용. 멱등은 SQL로 직접 보장</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">data.sql과 Flyway는 충돌하기 쉽다</span>\n<p>Flyway를 쓰는 프로젝트에서 <code>data.sql</code>(Spring SQL 초기화)을 함께 켜면 <em>실행 시점이 어긋납니다</em> — 기본 설정에서 Hibernate/Spring의 SQL 초기화가 Flyway보다 먼저 돌아 \"테이블 없음\" 에러가 날 수 있습니다. 굳이 함께 쓰려면 <code>spring.jpa.defer-datasource-initialization=true</code>로 순서를 미뤄야 합니다. 깔끔한 선택은 <strong>시드도 Flyway로 일원화(<code>R__</code>)하거나, Java 시더로 분리</strong>하는 것입니다. 환경도 가려 받으세요 — 시더에 <code>@Profile(\"local\")</code>을 붙여 운영에서는 절대 안 돌게.</p>\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">권장 분리 — 환경별 책임</span>\n<span class=\"dim\">구조(모든 환경)&nbsp;&nbsp;&nbsp;</span> Flyway V__&nbsp;&nbsp;&lt;- 마이그레이션<br>\n<span class=\"dim\">참조 데이터(공통)&nbsp;&nbsp;</span> Flyway R__&nbsp;&nbsp;&lt;- 코드값·ENUM 테이블 등 모든 환경 필요분<br>\n<span class=\"dim\">개발용 샘플(local)&nbsp;</span> <span class=\"seg\">@Profile(\"local\")</span> 시더&nbsp;&nbsp;&lt;- 로그인 계정·더미 거래 등\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"dbseed-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEED-05</span><h2>멱등 시더 작성</h2></div>\n<p class=\"lede\">멱등(idempotent)은 <em>몇 번 실행해도 결과가 같은</em> 성질입니다. 시더가 멱등이면 \"DB를 날렸다가 재구동\" 한 번으로 항상 같은 깨끗한 상태로 돌아옵니다 — 안전한 비상 복구의 전제입니다. 멱등이 아니면 두 번째 실행에서 PK 충돌로 기동이 깨집니다.</p>\n<h3><span class=\"h3-tag\">5.1</span>존재 확인 후 저장</h3>\n<div class=\"serial-card\">\n<span class=\"sc-label\">LocalDataSeeder.java — existsBy 패턴</span>\n<span class=\"seg2\">@Component</span><br>\n<span class=\"seg2\">@Profile(\"local\")</span>&nbsp;&nbsp;<span class=\"dim\">// 운영 프로파일에선 빈 자체가 안 생김</span><br>\n<span class=\"seg\">public class</span> LocalDataSeeder <span class=\"seg\">implements</span> CommandLineRunner {<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg\">private final</span> ProjectRepository projects;<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Override</span><br>\n&nbsp;&nbsp;<span class=\"seg\">public void</span> run(String... args) {<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"dim\">// 이미 있으면 건너뜀 -&gt; 재실행해도 행이 안 늘어남</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">if</span> (projects.existsByCode(<span class=\"seg2\">\"GM-001\"</span>)) <span class=\"seg\">return</span>;<br>\n<br>\n&nbsp;&nbsp;&nbsp;&nbsp;projects.save(<span class=\"seg\">new</span> Project(<span class=\"seg2\">\"GM-001\"</span>, <span class=\"seg2\">\"지역 포인트 정산 시범\"</span>));<br>\n&nbsp;&nbsp;}<br>\n}\n</div>\n<h3><span class=\"h3-tag\">5.2</span>고정 ID + upsert</h3>\n<p>행이 늘지 않는 것만이 아니라 <em>내용까지 항상 같게</em> 맞추려면, 고정 ID로 \"있으면 갱신, 없으면 삽입\"(upsert)을 합니다. 시드를 고치면 다음 실행 때 갱신이 반영됩니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">R__seed_reference.sql — Postgres ON CONFLICT</span>\n<span class=\"dim\">-- 고정 ID로 upsert: 재적용해도 행 수·값이 동일</span><br>\nINSERT INTO credit_status (id, code, label)<br>\nVALUES<br>\n&nbsp;&nbsp;(1, <span class=\"seg2\">'PENDING'</span>, <span class=\"seg2\">'심사대기'</span>),<br>\n&nbsp;&nbsp;(2, <span class=\"seg2\">'APPROVED'</span>, <span class=\"seg2\">'승인'</span>)<br>\nON CONFLICT (id) DO UPDATE<br>\n&nbsp;&nbsp;SET code = EXCLUDED.code, label = EXCLUDED.label;\n</div>\n<table>\n<tr><th>전략</th><th>언제 / 보장 범위</th></tr>\n<tr><td><code>existsByX</code> 후 저장</td><td>\"없을 때만 1회\". 코드 분기 필요 시. 내용 변경은 반영 안 됨</td></tr>\n<tr><td>upsert(<code>ON CONFLICT</code> / <code>MERGE</code>)</td><td>행 수 + 내용까지 고정. 시드를 고치면 갱신 전파</td></tr>\n<tr><td>고정 ID 사용</td><td>upsert·FK 참조의 기준점. 자동증가에 맡기면 매번 ID가 바뀜</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">왜 멱등이어야 하나</span>\n<p>비멱등 시더는 첫 실행만 성공하고 두 번째부터 깨지는 <em>지뢰</em>입니다. 멱등이면 시더를 항상 켜둘 수 있고, 누구든 로컬 DB를 날렸다 재구동하면 같은 상태로 복구됩니다. \"내 컴퓨터에선 되는데\" 문제의 큰 축 하나를 제거합니다 — 모두가 동일한 시드 결과 위에서 일하기 때문입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"dbseed-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEED-06</span><h2>로컬 리셋 워크플로우</h2></div>\n<p class=\"lede\">로컬 데이터가 꼬였을 때 가장 빠른 회복은 \"깨끗이 지우고 처음부터 다시 세우기\"입니다. 멱등 시더(→ SEED-05)와 Flyway(→ SEED-02)가 갖춰져 있으면 이건 명령 몇 줄로 끝납니다.</p>\n<div class=\"flow\">\n<span class=\"step\">앱 정상 종료</span><span class=\"arr\">→</span>\n<span class=\"step hl\">DB 초기화</span><span class=\"arr\">→</span>\n<span class=\"step\">재구동</span><span class=\"arr\">→</span>\n<span class=\"step\">Flyway 재적용</span><span class=\"arr\">→</span>\n<span class=\"step hl\">시더 자동 복구</span>\n</div>\n<div class=\"serial-card\">\n<span class=\"sc-label\">reset-local-db.sh — 로컬 전용 (docker-compose Postgres 예시)</span>\n<span class=\"dim\">#!/usr/bin/env bash</span><br>\n<span class=\"seg\">set</span> -euo pipefail<br>\n<br>\n<span class=\"dim\"># 1) 앱 종료는 사람이 먼저 (열린 커넥션 정리)</span><br>\n<span class=\"dim\"># 2) 스키마 통째로 비우기 — public 스키마를 drop 후 재생성</span><br>\ndocker compose exec -T db psql -U postgres -d app_local \\<br>\n&nbsp;&nbsp;-c <span class=\"seg2\">\"DROP SCHEMA public CASCADE; CREATE SCHEMA public;\"</span><br>\n<br>\n<span class=\"dim\"># 3) 재구동하면 Flyway가 V__ 전부 재적용, @Profile(\"local\") 시더가 데이터 복구</span><br>\n./gradlew bootRun --args=<span class=\"seg2\">'--spring.profiles.active=local'</span>\n</div>\n<p>볼륨째 날리는 방식(<code>docker compose down -v</code> 후 <code>up</code>)도 같은 결과를 줍니다 — DB 컨테이너의 데이터 볼륨을 삭제하면 다음 기동 때 빈 DB로 시작합니다. 어느 쪽이든 핵심은 <em>재구동 한 번이 Flyway 적용 + 시드 복구를 자동으로 한다는 것</em>입니다.</p>\n<div class=\"callout risk\">\n<span class=\"co-label\">운영 절대 금지 — 이 스크립트는 로컬 전용</span>\n<p><code>DROP SCHEMA public CASCADE</code>는 <em>모든 테이블과 데이터를 영구 삭제</em>합니다. 운영 DB에서 실행되면 복구 불가입니다. 가드를 거세요 — ① 접속 문자열을 <code>localhost</code>/<code>app_local</code>로 하드코딩하고 운영 호스트면 즉시 종료, ② 스크립트 첫 줄에서 <code>SPRING_PROFILES_ACTIVE != local</code>이면 <code>exit 1</code>, ③ 운영 자격증명은 이 스크립트가 읽는 환경에 아예 두지 않기. 시더에 <code>@Profile(\"local\")</code>을 단 것과 같은 방어선을 셸 레벨에도 둡니다.</p>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">실무 플레이북</span>\n<p>\"로컬 DB가 이상해요\"의 표준 대응: ① 앱 종료 → ② <code>reset-local-db.sh</code> → ③ 재구동. 3분이면 끝나고, 결과는 누구 컴퓨터든 동일합니다. 이걸 README가 아니라 <em>한 줄 스크립트</em>로 만들어 두는 게 핵심 — 사람이 절차를 기억하지 않아도 되게. 마이그레이션이 꼬여 충돌이 났을 때도 가장 빠른 복구는 대개 전체 리셋입니다(운영이 아니므로 데이터를 잃어도 됩니다).</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"dbseed-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEED-07</span><h2>테스트 데이터</h2></div>\n<p class=\"lede\">테스트는 또 다른 환경입니다 — 빠르고, 격리되고, 매번 같은 상태여야 합니다. H2 같은 인메모리 DB는 빠르지만 Postgres와 SQL 방언이 달라 \"테스트는 통과하는데 운영에서 깨지는\" 함정을 만듭니다. 진짜 DB로 테스트하는 게 정석입니다.</p>\n<h3><span class=\"h3-tag\">7.1</span>Testcontainers — 진짜 DB로</h3>\n<p>Testcontainers는 테스트 중에 실제 PostgreSQL을 Docker 컨테이너로 띄웁니다. 운영과 같은 엔진·같은 Flyway 마이그레이션을 쓰므로, 방언 차이로 인한 거짓 통과가 사라집니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">RepositoryIT.java — Spring Boot + Testcontainers</span>\n<span class=\"seg2\">@SpringBootTest</span><br>\n<span class=\"seg2\">@Testcontainers</span><br>\n<span class=\"seg\">class</span> CreditRepositoryIT {<br>\n<br>\n&nbsp;&nbsp;<span class=\"seg2\">@Container</span>&nbsp;&nbsp;<span class=\"seg2\">@ServiceConnection</span>&nbsp;&nbsp;<span class=\"dim\">// 컨테이너 접속정보를 스프링에 자동 주입</span><br>\n&nbsp;&nbsp;<span class=\"seg\">static</span> PostgreSQLContainer&lt;?&gt; db =<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">new</span> PostgreSQLContainer&lt;&gt;(<span class=\"seg2\">\"postgres:16-alpine\"</span>);<br>\n<br>\n&nbsp;&nbsp;<span class=\"dim\">// Flyway가 컨테이너에 V__ 마이그레이션을 그대로 적용</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">@Test</span> <span class=\"seg\">void</span> findsByStatus() { <span class=\"dim\">/* ... */</span> }<br>\n}\n</div>\n<h3><span class=\"h3-tag\">7.2</span>테스트별 데이터 — @Sql</h3>\n<p>각 테스트가 필요한 데이터만 명시적으로 깔면, 테스트끼리 데이터를 공유해 생기는 미묘한 의존이 사라집니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">@Sql — 테스트 전/후 SQL 실행</span>\n<span class=\"seg2\">@Test</span><br>\n<span class=\"seg2\">@Sql(<span class=\"seg\">\"/sql/given-approved-credits.sql\"</span>)</span>&nbsp;&nbsp;<span class=\"dim\">// 이 테스트만의 fixture</span><br>\n<span class=\"seg\">void</span> countsApprovedCredits() { <span class=\"dim\">/* ... */</span> }\n</div>\n<table>\n<tr><th>도구</th><th>역할 / 왜</th></tr>\n<tr><td>Testcontainers</td><td>운영과 동일한 진짜 DB. 방언·제약·인덱스까지 실제처럼 검증</td></tr>\n<tr><td><code>@Sql</code></td><td>테스트별 fixture를 선언적으로. 데이터 의존을 테스트 안에 가둠</td></tr>\n<tr><td><code>@Transactional</code> 테스트</td><td>각 테스트가 끝나면 자동 롤백 → 다음 테스트는 깨끗한 상태에서 시작</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">테스트 격리</span>\n<p>테스트는 서로 영향을 주면 안 됩니다 — 한 테스트가 남긴 데이터가 다른 테스트를 통과·실패시키면 순서에 따라 결과가 바뀌는 flaky test가 됩니다. Spring의 테스트 메서드는 기본적으로 <code>@Transactional</code>이면 끝에서 롤백되어 격리됩니다. 다만 <code>@Commit</code>이나 별도 트랜잭션을 쓰는 경우는 직접 정리해야 합니다. 격리 원칙: <em>각 테스트는 자기가 필요한 데이터를 스스로 세우고, 끝나면 흔적을 남기지 않는다.</em></p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"dbseed-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">SEED-08</span><h2>치트시트</h2></div>\n<p class=\"lede\">손에 붙여둘 핵심 개념과 한 줄 규칙. 헷갈리면 여기서 찾으세요.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>ddl-auto 값</b><span>spring.jpa.hibernate</span></div><div class=\"g-def\"><code>none</code>·<code>validate</code>(운영) / <code>update</code>·<code>create</code>·<code>create-drop</code>(금지·실험용). 운영은 <code>validate</code>, 스키마는 Flyway가 소유</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Flyway 네이밍</b><span>V&lt;ver&gt;__&lt;desc&gt;.sql</span></div><div class=\"g-def\"><code>V1__init.sql</code> — V + 버전 + 언더스코어 <b>두 개</b> + 설명. 위치는 <code>db/migration</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>적용 순서</b><span>flyway_schema_history</span></div><div class=\"g-def\">버전 정렬 순으로 한 번씩. 이력 테이블에 체크섬·결과를 기록하고 미적용분만 실행</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>마이그레이션 불변</b><span>immutable migration</span></div><div class=\"g-def\">적용된 <code>V</code> 파일은 수정 금지 → 체크섬 mismatch. 변경은 새 <code>V</code> 파일 추가로</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>체크섬 충돌</b><span>flyway repair</span></div><div class=\"g-def\">이력의 체크섬을 현재 파일로 재기록. 잘못 머지된 파일 정리 등 예외 상황에만</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>expand-contract</b><span>무중단 변경</span></div><div class=\"g-def\">컬럼 추가 → 양쪽 쓰기 → 백필 → 읽기 전환 → 옛 컬럼 삭제. 각 단계가 별도 배포</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>R__ repeatable</b><span>R__seed.sql</span></div><div class=\"g-def\">체크섬이 바뀌면 매번 재적용되는 마이그레이션. 참조 데이터 시드에 적합</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>data.sql</b><span>Spring SQL init</span></div><div class=\"g-def\">가장 간단하나 멱등성 없음. Flyway와 순서 충돌 주의(<code>defer-datasource-initialization</code>)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>시더 컴포넌트</b><span>CommandLineRunner</span></div><div class=\"g-def\">기동 후 Java로 데이터 삽입. 조건 분기·Repository 재사용 가능. <code>@Profile(\"local\")</code> 필수</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>멱등</b><span>idempotent</span></div><div class=\"g-def\">몇 번 실행해도 같은 상태. <code>existsByX</code> 후 저장 / 고정 ID upsert(<code>ON CONFLICT</code>)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>로컬 리셋</b><span>drop &amp; reseed</span></div><div class=\"g-def\"><code>DROP SCHEMA public CASCADE</code> 후 재구동 → Flyway 재적용 + 시더 복구. <b>로컬 전용</b></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Testcontainers</b><span>real DB in test</span></div><div class=\"g-def\">테스트에 진짜 Postgres를 Docker로. 방언 차이 함정 제거. <code>@ServiceConnection</code>로 접속 자동 주입</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>@Sql</b><span>test fixture</span></div><div class=\"g-def\">테스트별 데이터를 SQL로 선언적 세팅. 데이터 의존을 테스트 안에 가둠</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>테스트 격리</b><span>rollback per test</span></div><div class=\"g-def\"><code>@Transactional</code> 테스트는 끝에서 자동 롤백. 테스트 간 데이터 공유 금지 → flaky 방지</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">한 장 요약</span>\n<p>스키마는 <strong>Flyway가 소유</strong>(JPA는 <code>validate</code>로 검증만), 변경은 <strong>새 V 파일</strong>로만(적용된 건 불변), 시더는 <strong>멱등 + <code>@Profile(\"local\")</code></strong>, 로컬은 <strong>리셋 한 줄로 자동 복구</strong>, 테스트는 <strong>Testcontainers로 진짜 DB + 롤백 격리</strong>. 이 다섯 줄이 이 문서 전부입니다.</p>\n</div>\n</section>\n\n<footer>\nDB SCHEMA &amp; LOCAL SEEDING GUIDE · V1 · 2026-06<br>\nSTACK : Spring Boot · JPA(Hibernate) · Flyway · PostgreSQL · Testcontainers<br>\nSCOPE : DDL · MIGRATION · SEED · COMPANION : BACKEND ENGINEERING HANDBOOK\n</footer>\n\n<section id=\"doc-cicd\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>CI/CD 배포</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : CICD-GUIDE-V1</span>\n    <span>SCOPE : PIPELINE · GITHUB ACTIONS · DEPLOY</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>CI/CD 배포<br>실무 가이드</h1>\n  <p class=\"hero-sub\">푸시하면 자동으로 빌드·테스트·배포 — 파이프라인을 손으로 짜보는 실무 가이드. 개념을 길게 설명하지 않고, <em>실제로 어떤 YAML을 어디에 두면 되는가</em>에 집중합니다. 각 단계마다 \"왜 이렇게 하는가\" 한 줄을 답니다. GitHub Actions 기준, Spring Boot(Gradle) + Docker 배포 흐름.</p>\n  <div class=\"hero-meta\">FOR : 프론트엔드 기반 풀스택 확장 · CI/CD 기초<br>DEPTH : 개념 깊이는 Docker·배포 핸드북으로 위임 · COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"cicd-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">CICD-01</span><h2>CI/CD가 하는 일</h2></div>\n<p class=\"lede\">한 줄로: <em>CI는 \"합칠 때마다 자동으로 빌드·테스트해 깨졌는지 검증\"</em>, <em>CD는 \"검증 통과한 코드를 자동으로 배포\"</em>. 사람이 손으로 하던 반복을 기계에 넘기는 것입니다.</p>\n<p><strong>CI</strong>(Continuous Integration)는 여러 사람이 각자 작업한 코드를 자주 합치되, 합칠 때마다 자동으로 빌드하고 테스트를 돌려 <em>깨진 채로 합쳐지는 것</em>을 막습니다. <strong>CD</strong>(Continuous Delivery/Deployment)는 그렇게 검증된 산출물을 스테이징·프로덕션으로 자동 배포합니다. 둘은 하나의 흐름이라 보통 CI/CD라 붙여 부릅니다.</p>\n<table>\n<tr><th>수동 배포의 문제</th><th>CI/CD가 주는 것</th></tr>\n<tr><td>매번 사람이 빌드·복사·재시작 → <b>단계 빠뜨림·오타</b></td><td>스크립트로 고정 → 항상 같은 순서로 실행</td></tr>\n<tr><td>\"내 컴퓨터에선 됐는데\" → <b>재현 불가</b></td><td>깨끗한 runner에서 매번 동일하게 빌드</td></tr>\n<tr><td>테스트를 깜빡하고 배포 → 운영 장애</td><td>테스트 통과해야만 배포(게이트, → CICD-06)</td></tr>\n<tr><td>배포 기록이 사람 머릿속에만 있음</td><td>누가·언제·무엇을 배포했는지 로그로 남음</td></tr>\n</table>\n<p>전형적인 파이프라인은 푸시 한 번으로 다음 단계들이 줄줄이 실행됩니다. 각 단계는 앞 단계가 성공해야만 다음으로 넘어갑니다 — 테스트가 깨지면 거기서 멈추고 이미지·배포로 가지 않습니다.</p>\n<div class=\"flow\">\n  <span class=\"step\">git push</span><span class=\"arr\">→</span>\n  <span class=\"step\">빌드</span><span class=\"arr\">→</span>\n  <span class=\"step\">테스트</span><span class=\"arr\">→</span>\n  <span class=\"step\">이미지 빌드·푸시</span><span class=\"arr\">→</span>\n  <span class=\"step hl\">배포</span>\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">이 가이드의 범위</span>\n<p>여기선 <em>파이프라인을 어떻게 짜는가</em>만 다룹니다. Docker 이미지의 내부 구조, 컨테이너 런타임, 배포 대상(서버·쿠버네티스) 자체의 동작은 깊이 들어가지 않습니다(→ Docker·배포 핸드북). CI/CD는 \"그 도구들을 자동으로 호출하는 오케스트레이션 레이어\"라고 보면 됩니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"cicd-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">CICD-02</span><h2>GitHub Actions 기본</h2></div>\n<p class=\"lede\">GitHub Actions의 작업 단위는 <em>workflow YAML 파일</em> 하나입니다. 리포지토리 안 정해진 위치에 두면, GitHub가 트리거 조건에 맞춰 알아서 실행합니다.</p>\n<p>워크플로우 파일은 반드시 <code>.github/workflows/</code> 디렉터리 안에 <code>*.yml</code>(또는 <code>*.yaml</code>)로 둬야 합니다 — 이 경로가 아니면 GitHub가 인식하지 않습니다. 파일 하나가 워크플로우 하나이고, 한 리포에 여러 개를 둘 수 있습니다(예: <code>ci.yml</code>, <code>deploy.yml</code>).</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">WORKFLOW 의 골격 — .github/workflows/ci.yml</span>\n<span class=\"seg\">name</span>: CI <span class=\"dim\"># Actions 탭에 표시될 이름</span><br>\n<span class=\"seg\">on</span>: <span class=\"dim\"># 언제 돌릴지 — 트리거</span><br>\n&nbsp;&nbsp;push:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;branches: [main]<br>\n<span class=\"seg\">jobs</span>: <span class=\"dim\"># 무엇을 할지 — 하나 이상의 job</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">build</span>: <span class=\"dim\"># job 이름(자유)</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;runs-on: ubuntu-latest <span class=\"dim\"># 어떤 runner(가상머신)에서</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;steps: <span class=\"dim\"># 순서대로 실행되는 단계들</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- uses: actions/checkout@v4 <span class=\"dim\"># 남이 만든 action 호출</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- run: echo \"hello\" <span class=\"dim\"># 셸 명령 직접 실행</span>\n</div>\n<table>\n<tr><th>키워드</th><th>의미 / 역할</th></tr>\n<tr><td><code>on</code></td><td><b>트리거</b> — 언제 워크플로우를 돌릴지. <code>push</code>, <code>pull_request</code>, <code>workflow_dispatch</code>(수동), <code>schedule</code>(주기) 등</td></tr>\n<tr><td><code>jobs</code></td><td>워크플로우가 하는 일의 묶음. job끼리는 <b>기본 병렬</b>, <code>needs</code>로 순서 지정</td></tr>\n<tr><td><code>runs-on</code></td><td>job이 돌 <b>runner</b> 지정 — <code>ubuntu-latest</code>가 표준. 매 실행마다 깨끗한 새 VM</td></tr>\n<tr><td><code>steps</code></td><td>job 안에서 <b>위에서 아래로</b> 순차 실행. 하나라도 실패하면 그 job 중단</td></tr>\n<tr><td><code>uses</code></td><td>마켓플레이스의 재사용 <b>action</b> 호출 (예: <code>actions/checkout@v4</code>)</td></tr>\n<tr><td><code>run</code></td><td>runner 셸에서 <b>명령 직접 실행</b> (예: <code>./gradlew build</code>)</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">runner = 매번 새로 만들어지는 깨끗한 가상머신</span>\n<p>runner는 job이 시작될 때 생성되고 끝나면 <em>버려지는</em> 일회용 VM입니다. 그래서 \"내 로컬에 깔려 있던 것\"에 의존할 수 없고, 필요한 런타임(JDK 등)은 매번 step에서 설치해야 합니다. 이게 CI의 핵심 가치인 <strong>재현성</strong>의 출처입니다 — 항상 동일한 빈 상태에서 시작하니까요. 대신 매번 새로 설치하면 느려지므로 <em>캐시</em>로 보완합니다(→ CICD-03).</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"cicd-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">CICD-03</span><h2>빌드·테스트 워크플로우</h2></div>\n<p class=\"lede\">가장 먼저 만들 워크플로우는 <em>\"푸시·PR마다 빌드하고 테스트를 돌리는\"</em> CI입니다. Spring Boot + Gradle 기준으로 실제 동작하는 <code>ci.yml</code>을 통째로 봅니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">.github/workflows/ci.yml — 빌드 &amp; 테스트</span>\n<span class=\"seg\">name</span>: CI<br>\n<br>\n<span class=\"seg\">on</span>:<br>\n&nbsp;&nbsp;push:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;branches: [main]<br>\n&nbsp;&nbsp;pull_request: <span class=\"dim\"># PR이 열릴 때마다 검증 → 깨진 코드 머지 차단</span><br>\n<br>\n<span class=\"seg\">jobs</span>:<br>\n&nbsp;&nbsp;<span class=\"seg2\">build</span>:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;runs-on: ubuntu-latest<br>\n&nbsp;&nbsp;&nbsp;&nbsp;steps:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- uses: actions/checkout@v4 <span class=\"dim\"># 리포 코드를 runner로 가져옴</span><br>\n<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- name: Set up JDK 21<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;uses: actions/setup-java@v4<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;with:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;distribution: temurin <span class=\"dim\"># Eclipse Temurin JDK 배포판</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;java-version: '21'<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;cache: gradle <span class=\"dim\"># Gradle 의존성 캐시 자동 — 재설치 시간 단축</span><br>\n<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- name: Grant execute permission<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;run: chmod +x ./gradlew <span class=\"dim\"># 래퍼 실행 권한 부여</span><br>\n<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- name: Build &amp; Test<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;run: ./gradlew build <span class=\"dim\"># build는 test를 포함 — 컴파일+테스트 한 번에</span>\n</div>\n<table>\n<tr><th>step</th><th>무엇을 / 왜</th></tr>\n<tr><td><code>actions/checkout@v4</code></td><td>리포 소스를 runner로 클론. <b>이게 없으면 코드가 없어</b> 아무것도 못 함. 거의 모든 워크플로우의 첫 step</td></tr>\n<tr><td><code>actions/setup-java@v4</code></td><td>지정 JDK를 runner에 설치하고 <code>JAVA_HOME</code> 설정. <code>distribution: temurin</code>이 가장 흔함</td></tr>\n<tr><td><code>cache: gradle</code></td><td>setup-java 내장 옵션. <code>~/.gradle</code> 의존성을 캐싱해 다음 실행을 단축. <b>왜</b>: runner는 매번 비어 있어서 캐시 없으면 매번 전부 다운로드</td></tr>\n<tr><td><code>./gradlew build</code></td><td>Gradle wrapper로 컴파일+테스트. <code>build</code>는 <code>test</code>를 의존하므로 테스트 실패 시 전체 실패 → 빨간 X</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">왜 gradlew(wrapper)인가</span>\n<p>전역 <code>gradle</code>이 아니라 리포에 포함된 <code>./gradlew</code>를 쓰는 이유는 <em>Gradle 버전을 리포가 고정</em>하기 때문입니다 — runner든 동료 노트북이든 같은 Gradle로 빌드되어 재현성이 보장됩니다. <code>test</code>만 따로 돌리려면 <code>./gradlew test</code>, 빌드 캐시 문제를 의심하면 <code>--no-daemon</code>을 붙이는 정도만 알아두면 됩니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"cicd-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">CICD-04</span><h2>이미지 빌드·푸시</h2></div>\n<p class=\"lede\">테스트가 통과하면 배포할 <em>산출물</em>을 만듭니다. 컨테이너 기반 배포라면 그 산출물은 Docker 이미지이고, 레지스트리(이미지 저장소)에 푸시합니다.</p>\n<p>흐름은 셋입니다 — ① 레지스트리에 <strong>로그인</strong>, ② 이미지 <strong>빌드</strong>, ③ <strong>푸시</strong>. GitHub Actions에선 공식 <code>docker/build-push-action</code>이 빌드와 푸시를 한 step으로 묶어줍니다. 로그인은 <code>docker/login-action</code>을 씁니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">.github/workflows/deploy.yml — 이미지 빌드 &amp; 푸시 (job 일부)</span>\n&nbsp;&nbsp;<span class=\"seg2\">docker</span>:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;needs: build <span class=\"dim\"># build job 성공 후에만 — 테스트 통과 게이트</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;runs-on: ubuntu-latest<br>\n&nbsp;&nbsp;&nbsp;&nbsp;steps:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- uses: actions/checkout@v4<br>\n<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- name: Log in to registry<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;uses: docker/login-action@v3<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;with:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;registry: ghcr.io <span class=\"dim\"># GitHub Container Registry</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;username: ${{ github.actor }}<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;password: ${{ secrets.GITHUB_TOKEN }} <span class=\"dim\"># 시크릿 — 평문 금지(→CICD-05)</span><br>\n<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- name: Build and push<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;uses: docker/build-push-action@v6<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;with:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;context: .<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;push: true<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;tags: | <span class=\"dim\"># 두 태그를 동시에 — 추적용 sha + 최신 latest</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;ghcr.io/${{ github.repository }}:${{ github.sha }}<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;ghcr.io/${{ github.repository }}:latest\n</div>\n<table>\n<tr><th>요소</th><th>의미 / 왜</th></tr>\n<tr><td><code>needs: build</code></td><td>build job이 성공해야만 이 job 시작 → <b>테스트 깨지면 이미지 안 만듦</b></td></tr>\n<tr><td><code>docker/login-action@v3</code></td><td>레지스트리 인증. credential은 반드시 <code>${{ secrets.X }}</code>로 주입</td></tr>\n<tr><td><code>docker/build-push-action@v6</code></td><td>빌드+푸시를 한 번에. <code>context</code>는 Dockerfile 위치, <code>push: true</code>면 레지스트리로 전송</td></tr>\n<tr><td><code>:${{ github.sha }}</code></td><td><b>커밋 SHA 태그</b> — 어떤 코드로 만든 이미지인지 정확히 추적. 롤백·디버깅의 핵심</td></tr>\n<tr><td><code>:latest</code></td><td>\"가장 최신\" 포인터. 편하지만 <b>어떤 버전인지 모호</b> — sha 태그와 병행</td></tr>\n</table>\n<div class=\"callout warn\">\n<span class=\"co-label\">latest 태그만 쓰지 말 것</span>\n<p><code>:latest</code> 하나만 쓰면 \"지금 운영에 떠 있는 게 정확히 어떤 커밋인지\" 알 수 없고, 롤백할 과거 버전을 가리킬 수도 없습니다. <strong>항상 <code>${{ github.sha }}</code> 같은 불변 태그를 함께 박으세요</strong> — 사고가 나면 \"그 sha로 다시 배포\"가 가능해집니다. 이미지 빌드 자체(Dockerfile 작성·레이어 최적화)는 → Docker 핸드북.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"cicd-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">CICD-05</span><h2>시크릿·환경</h2></div>\n<p class=\"lede\">토큰·비밀번호·DB 접속정보는 <em>절대 YAML이나 코드에 평문으로 쓰지 않습니다</em>. GitHub repo Secrets에 저장하고, 워크플로우에선 <code>${{ secrets.X }}</code>로 참조만 합니다.</p>\n<p>저장 위치는 리포의 <em>Settings → Secrets and variables → Actions</em>입니다. 여기 등록한 값은 암호화되어 보관되고, 워크플로우 실행 시점에만 주입되며, 로그에 찍히면 <code>***</code>로 자동 마스킹됩니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">시크릿 참조 — 평문 금지</span>\n<span class=\"dim\"># 나쁜 예 — 절대 금지</span><br>\n&nbsp;&nbsp;password: ghp_aBcD1234realtoken <span class=\"dim\"># 평문 노출 = 즉시 유출</span><br>\n<br>\n<span class=\"dim\"># 좋은 예 — Secrets 참조</span><br>\n&nbsp;&nbsp;password: ${{ secrets.DOCKER_TOKEN }}<br>\n<br>\n<span class=\"dim\"># step에 환경변수로 주입</span><br>\n&nbsp;&nbsp;- name: Deploy<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">env</span>:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;DB_PASSWORD: ${{ secrets.DB_PASSWORD }}<br>\n&nbsp;&nbsp;&nbsp;&nbsp;run: ./deploy.sh\n</div>\n<table>\n<tr><th>종류</th><th>의미 / 언제</th></tr>\n<tr><td><code>${{ secrets.X }}</code></td><td>리포에 등록한 암호화 시크릿. credential·토큰·키 전부 이걸로</td></tr>\n<tr><td><code>${{ secrets.GITHUB_TOKEN }}</code></td><td>GitHub가 <b>자동 제공</b>하는 토큰. 같은 리포의 ghcr 푸시 등에 별도 등록 없이 사용</td></tr>\n<tr><td>Environment secrets</td><td><b>environment별로 분리</b> 저장(staging/production). 같은 이름 다른 값 + 승인 게이트(→CICD-06)</td></tr>\n<tr><td><code>${{ vars.X }}</code></td><td>비밀 아닌 설정값(Variables). API URL·플래그 등. 마스킹 안 됨</td></tr>\n</table>\n<div class=\"callout risk\">\n<span class=\"co-label\">절대 하지 말 것</span>\n<p>① 토큰·비밀번호를 YAML·소스코드·커밋 메시지에 <strong>평문으로 쓰지 마세요</strong> — 한 번 푸시되면 git 히스토리에 영구히 남아, 지워도 유출로 간주하고 즉시 폐기·재발급해야 합니다. ② 시크릿을 <code>echo \"$TOKEN\"</code>으로 일부러 출력하지 마세요 — 마스킹을 우회하면 로그에 새어 나갑니다. ③ PR을 fork에서 받는 공개 리포는 시크릿 접근 정책을 따로 확인하세요(악의적 PR이 시크릿을 빼갈 수 있는 표면).</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"cicd-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">CICD-06</span><h2>배포 트리거·전략</h2></div>\n<p class=\"lede\">\"언제 배포할 것인가\"를 정하는 게 CD 설계의 핵심입니다. main 푸시마다? 태그를 달 때만? 사람 승인을 거쳐서? — 트리거와 게이트로 표현합니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">트리거 패턴들 — on:</span>\n<span class=\"dim\"># 1) main에 머지되면 staging 배포</span><br>\n<span class=\"seg\">on</span>:<br>\n&nbsp;&nbsp;push:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;branches: [main]<br>\n<br>\n<span class=\"dim\"># 2) v1.2.3 같은 버전 태그를 달면 production 배포</span><br>\n<span class=\"seg\">on</span>:<br>\n&nbsp;&nbsp;push:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;tags: ['v*'] <span class=\"dim\"># 의도적 릴리스만 트리거 → 실수 배포 방지</span><br>\n<br>\n<span class=\"dim\"># 3) 버튼으로 수동 실행</span><br>\n<span class=\"seg\">on</span>: workflow_dispatch\n</div>\n<p>배포 job에 <code>environment</code>를 지정하면 GitHub의 <em>승인 게이트</em>를 걸 수 있습니다 — production environment에 \"required reviewers\"를 설정해두면, 배포 job이 그 지점에서 멈추고 지정된 사람이 승인해야 진행됩니다.</p>\n<div class=\"serial-card\">\n<span class=\"sc-label\">승인 게이트 + 테스트 통과 게이트</span>\n&nbsp;&nbsp;<span class=\"seg2\">deploy-prod</span>:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;needs: [build, docker] <span class=\"dim\"># 빌드·테스트·이미지 다 성공해야만</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;runs-on: ubuntu-latest<br>\n&nbsp;&nbsp;&nbsp;&nbsp;<span class=\"seg\">environment</span>: production <span class=\"dim\"># 이 환경에 승인 게이트 설정 → 사람 승인 대기</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;steps:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;- run: ./deploy.sh ${{ github.sha }}\n</div>\n<table>\n<tr><th>전략 / 장치</th><th>의미 / 왜</th></tr>\n<tr><td>branch 트리거</td><td><code>main</code> 머지 = 자동 staging 배포. 빠른 피드백, 낮은 위험</td></tr>\n<tr><td>tag 트리거</td><td><code>v*</code> 태그 = production 배포. <b>의도적 릴리스만</b> — 실수로 운영 안 나감</td></tr>\n<tr><td>승인 게이트</td><td><code>environment</code> + required reviewers. 운영 배포 전 <b>사람의 마지막 확인</b></td></tr>\n<tr><td>테스트 통과 게이트</td><td><code>needs:</code>로 배포를 빌드·테스트 job 뒤에 묶음 → <b>깨진 코드는 배포 불가</b></td></tr>\n<tr><td>롤백</td><td>과거 sha 이미지로 재배포. 그래서 sha 태그가 필수(→CICD-04)</td></tr>\n</table>\n<div class=\"callout\">\n<span class=\"co-label\">롤백은 \"이전 sha로 다시 배포\"</span>\n<p>새 배포가 잘못되면, 빌드를 새로 하지 않고 <em>직전에 잘 돌던 커밋 sha 이미지를 다시 배포</em>하는 게 가장 빠르고 안전한 롤백입니다 — 이미 검증된 산출물이니까요. 그래서 모든 이미지에 불변 sha 태그를 박아두는 게 롤백 전략의 전제 조건입니다. blue-green·canary 같은 무중단 배포 전략은 → 배포 핸드북.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"cicd-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">CICD-07</span><h2>파이프라인 베스트 프랙티스</h2></div>\n<p class=\"lede\">파이프라인은 짜는 것보다 <em>유지하는 것</em>이 일입니다. 느리거나 자주 깨지는 CI는 사람들이 우회하기 시작하면서 가치가 사라집니다. 몇 가지 원칙.</p>\n<table>\n<tr><th>원칙</th><th>왜 / 어떻게</th></tr>\n<tr><td><b>빠른 피드백 우선</b></td><td>빠른 검사(lint·unit test)를 앞에, 느린 것(E2E·이미지 빌드)을 뒤에. 깨질 거면 <b>빨리 깨져야</b> 개발자 대기 시간이 준다</td></tr>\n<tr><td><b>캐시로 시간 단축</b></td><td>의존성(<code>cache: gradle</code>)·Docker 레이어를 캐싱. runner는 매번 비어서 캐시 없으면 매번 풀다운로드</td></tr>\n<tr><td><b>job 병렬화</b></td><td>독립적인 검사(테스트·lint·보안 스캔)는 별도 job으로 동시 실행. 전체 시간 단축</td></tr>\n<tr><td><b>실패 시 후속 차단</b></td><td><code>needs:</code>로 의존을 명시 → 앞이 깨지면 뒤(배포)는 시작 안 함. 깨진 걸 내보내지 않는 안전장치</td></tr>\n<tr><td><b>비밀 노출 주의</b></td><td>시크릿은 항상 <code>${{ secrets.X }}</code>, 로그에 출력 금지, fork PR 권한 확인(→CICD-05)</td></tr>\n<tr><td><b>워크플로우도 코드</b></td><td>YAML 변경도 PR·리뷰 대상. action은 버전 핀(<code>@v4</code>)으로 고정해 갑작스런 동작 변화 방지</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">병렬 검사 + 게이트 결합 예시</span>\n<span class=\"seg\">jobs</span>:<br>\n&nbsp;&nbsp;<span class=\"seg2\">test</span>: <span class=\"dim\"># ┐</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;runs-on: ubuntu-latest <span class=\"dim\"># │ 둘이 동시에 돌아(병렬)</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">lint</span>: <span class=\"dim\"># ┘ 전체 시간 = 둘 중 느린 쪽</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;runs-on: ubuntu-latest<br>\n&nbsp;&nbsp;<span class=\"seg2\">deploy</span>:<br>\n&nbsp;&nbsp;&nbsp;&nbsp;needs: [test, lint] <span class=\"dim\"># 둘 다 통과해야만 배포 — 게이트</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;runs-on: ubuntu-latest\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">느린 CI는 죽은 CI</span>\n<p>CI가 매번 20분 걸리면 개발자는 결과를 안 기다리고 다음 작업으로 넘어가버리고, 깨진 빌드가 방치됩니다. <strong>캐시·병렬화로 핵심 검사를 몇 분 안에</strong> 끝내는 걸 목표로 하세요. 그리고 flaky한(가끔 실패하는) 테스트는 즉시 격리하거나 고치세요 — \"또 그 테스트네\" 하고 빨간 X를 무시하기 시작하면 CI 신뢰가 통째로 무너집니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"cicd-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">CICD-08</span><h2>치트시트 — GitHub Actions 핵심</h2></div>\n<p class=\"lede\">실무에서 반복 참조하는 조각들. 전부 외우지 말고 \"이런 게 있다\"만 알아두고 필요할 때 찾으세요.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>워크플로우 위치</b><span>where</span></div><div class=\"g-def\"><code>.github/workflows/*.yml</code> — 이 경로 아니면 GitHub가 인식 안 함. 파일 하나 = 워크플로우 하나</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>트리거</b><span>on</span></div><div class=\"g-def\"><code>on: push</code> / <code>on: pull_request</code> / <code>on: workflow_dispatch</code>(수동) / <code>on: { push: { tags: ['v*'] } }</code>(태그)</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>job 골격</b><span>jobs / runs-on</span></div><div class=\"g-def\"><code>jobs.build.runs-on: ubuntu-latest</code> + <code>steps:</code>. job끼리 기본 병렬, <code>needs:</code>로 순서</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>코드 체크아웃</b><span>checkout</span></div><div class=\"g-def\"><code>- uses: actions/checkout@v4</code> — 거의 모든 워크플로우의 첫 step. 없으면 코드가 없음</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>JDK 설치</b><span>setup-java</span></div><div class=\"g-def\"><code>actions/setup-java@v4</code> + <code>with: { distribution: temurin, java-version: '21', cache: gradle }</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Gradle 빌드·테스트</b><span>gradlew</span></div><div class=\"g-def\"><code>./gradlew build</code> (test 포함) / <code>./gradlew test</code>. wrapper로 버전 고정 → 재현성</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>의존성 캐시</b><span>cache: gradle</span></div><div class=\"g-def\">setup-java 내장 <code>cache: gradle</code>. runner는 매번 비어서 캐시로 재설치 시간 단축</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>레지스트리 로그인</b><span>login-action</span></div><div class=\"g-def\"><code>docker/login-action@v3</code> + <code>registry / username / password: ${{ secrets.X }}</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>이미지 빌드·푸시</b><span>build-push-action</span></div><div class=\"g-def\"><code>docker/build-push-action@v6</code> + <code>push: true</code>, <code>tags:</code>에 sha와 latest 병행</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>시크릿 참조</b><span>secrets</span></div><div class=\"g-def\"><code>${{ secrets.NAME }}</code> — Settings→Secrets에 등록. 평문 금지, 로그 자동 마스킹. <code>${{ secrets.GITHUB_TOKEN }}</code>은 자동 제공</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>실행 순서·게이트</b><span>needs</span></div><div class=\"g-def\"><code>needs: [build, test]</code> — 지정 job 성공 후에만 실행. \"테스트 통과해야만 배포\"의 핵심</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>환경·승인 게이트</b><span>environment</span></div><div class=\"g-def\"><code>environment: production</code> + required reviewers → 운영 배포 전 사람 승인 대기. env별 시크릿 분리</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>버전 태그 트리거</b><span>tags</span></div><div class=\"g-def\"><code>on: { push: { tags: ['v*'] } }</code> — 의도적 릴리스만 production 트리거</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>롤백</b><span>rollback</span></div><div class=\"g-def\">과거 <code>:${{ github.sha }}</code> 이미지로 재배포. 새 빌드 없이 검증된 산출물로 복귀</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">학습 순서 제안</span>\n<p>한 번에 다 만들지 마세요. ① 먼저 <code>ci.yml</code>로 <em>빌드·테스트만</em> 자동화(CICD-03) — 여기서 PR마다 빨간/초록이 뜨는 것만으로도 가치가 큽니다. ② 그다음 이미지 빌드·푸시(CICD-04)와 시크릿(CICD-05)을 붙이고, ③ 마지막으로 배포 트리거·승인 게이트(CICD-06)를 올립니다. 각 단계가 독립적으로 동작하니 점진적으로 쌓으세요. 이미지·배포 대상 자체의 동작은 → Docker·배포 핸드북에서 이어집니다.</p>\n</div>\n</section>\n\n<footer>\nCI/CD 배포 실무 가이드 · V1 · 2026-06<br>\nSCOPE : GITHUB ACTIONS · BUILD · TEST · DOCKER IMAGE · DEPLOY<br>\nNOTE : 실재하는 action·문법만 사용(actions/checkout · setup-java · docker/build-push-action) · COMPANION : DOCKER·배포 핸드북\n</footer>\n\n<section id=\"doc-logs\">\n<div class=\"ch-head\"><span class=\"ch-code\">SOURCE</span><h2>로그·커스텀 명령</h2></div>\n</section>\n\n<header class=\"hero\">\n  <div class=\"hero-serial\">\n    <span>DOC : LOGTL-GUIDE-V1</span>\n    <span>SCOPE : LOG QUERY · ALIAS · SCRIPTS</span>\n    <span>LANG : KO</span>\n  </div>\n  <h1>로그 조회·커스텀 명령<br>실무 가이드</h1>\n  <p class=\"hero-sub\">로그에서 원인을 빠르게 찾고, 반복 작업을 명령 한 줄로 만드는 실무 가이드. 명령·스크립트가 중심이고, 각 단계엔 <em>왜 그렇게 하는지</em> 한 줄을 붙였습니다. macOS·zsh·Docker·Spring 환경 기준 — 리눅스 핸드북·관측가능성 핸드북과 함께 보세요.</p>\n  <div class=\"hero-meta\">ENV : macOS(Darwin) · zsh · Docker · Spring Boot · Gradle<br>COMPILED : 2026-06</div>\n</header>\n\n<!-- ============ CH 1 ============ -->\n<section id=\"logs-ch1\">\n<div class=\"ch-head\"><span class=\"ch-code\">LOGTL-01</span><h2>로그를 어디서 보나</h2></div>\n<p class=\"lede\">디버깅의 첫 질문은 항상 같습니다 — <em>\"이 로그는 어디로 나가는가.\"</em> 콘솔인가, 파일인가, 컨테이너 안인가, systemd가 받아가는가, 클라우드로 흘러가는가. 출처를 먼저 정해야 다음 명령이 정해집니다.</p>\n<table>\n<tr><th>실행 환경</th><th>어디서 보나 / 명령</th><th>왜</th></tr>\n<tr><td>로컬 IDE·터미널</td><td>표준 출력 콘솔. 파일로 쓰면 <code>tail -f logs/app.log</code></td><td>가장 직접적 — Spring은 기본이 콘솔, <code>logging.file.name</code> 설정 시 파일로</td></tr>\n<tr><td>Docker 컨테이너(단일)</td><td><code>docker logs -f &lt;c&gt;</code></td><td>컨테이너 stdout/stderr를 Docker가 캡처 — <code>-f</code>로 실시간 추적</td></tr>\n<tr><td>Docker Compose(다중)</td><td><code>docker compose logs -f &lt;svc&gt;</code></td><td>서비스 이름으로 골라봄 — 서비스 여러 개를 한 번에 또는 하나만</td></tr>\n<tr><td>systemd 서비스</td><td><code>journalctl -u &lt;svc&gt; -f</code></td><td>리눅스 서버에서 서비스로 등록된 프로세스의 로그는 journal이 모음</td></tr>\n<tr><td>클라우드(ECS/Cloud Run 등)</td><td>CloudWatch · GCP Logging 콘솔, 또는 CLI</td><td>컨테이너가 사라져도 로그는 남음 — 운영 사고 분석의 원본</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">실행 환경별 로그 추적 — 첫 명령</span>\n<span class=\"dim\"># 단일 컨테이너 — 마지막 100줄부터 실시간으로</span><br>\ndocker logs <span class=\"seg2\">-f --tail 100</span> <span class=\"seg\">myapp</span><br>\n<br>\n<span class=\"dim\"># compose — api 서비스만, 타임스탬프 붙여서</span><br>\ndocker compose logs <span class=\"seg2\">-f -t</span> <span class=\"seg\">api</span><br>\n<br>\n<span class=\"dim\"># systemd — 부팅 이후 + 실시간</span><br>\njournalctl <span class=\"seg2\">-u</span> <span class=\"seg\">myapp.service</span> <span class=\"seg2\">-b -f</span><br>\n<br>\n<span class=\"dim\"># 컨테이너 ID/이름을 모를 때 — 먼저 목록부터</span><br>\ndocker ps <span class=\"dim\">|</span> grep <span class=\"seg\">api</span>\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">먼저 정할 것</span>\n<p>로그를 못 찾는 가장 흔한 이유는 <em>엉뚱한 출처</em>를 보는 것입니다. 컨테이너로 돌리면서 로컬 파일을 <code>tail</code>하거나, compose로 띄워놓고 <code>docker logs</code>로 단일 컨테이너를 찾는 식. \"지금 이 프로세스가 어떻게 떠 있나\"(IDE / docker / compose / systemd)를 먼저 확정하고, 그에 맞는 한 줄을 고르세요. 컨테이너 안에서 직접 봐야 하면 <code>docker exec -it &lt;c&gt; sh</code>로 들어가 파일을 <code>tail</code>합니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 2 ============ -->\n<section id=\"logs-ch2\">\n<div class=\"ch-head\"><span class=\"ch-code\">LOGTL-02</span><h2>로그 필터링</h2></div>\n<p class=\"lede\">로그는 보는 게 아니라 <em>좁히는</em> 것입니다. 수천 줄에서 의미 있는 줄은 보통 몇 개 — <code>grep</code>/<code>rg</code>로 깎고, 실시간이면 <code>tail -f | grep</code>, 탐색이면 <code>less +F</code>로 흐름과 검색을 오갑니다.</p>\n<table>\n<tr><th>목적</th><th>명령</th><th>왜</th></tr>\n<tr><td>에러만 추리기</td><td><code>grep -i error app.log</code></td><td><code>-i</code>로 ERROR/Error/error 모두 — 대소문자에 안 흔들림</td></tr>\n<tr><td>앞뒤 맥락까지</td><td><code>grep -C 3 \"NullPointer\" app.log</code></td><td>에러 한 줄만 보면 원인을 모름 — <code>-C 3</code>으로 전후 3줄</td></tr>\n<tr><td>특정 요청 추적</td><td><code>grep \"userId=42\" app.log</code></td><td>한 사용자·한 주문의 흐름만 — 노이즈 제거</td></tr>\n<tr><td>제외하며 보기</td><td><code>grep -v \"health\" app.log</code></td><td>헬스체크 같은 반복 노이즈를 빼고 봄(<code>-v</code>=반대)</td></tr>\n<tr><td>실시간 + 필터</td><td><code>tail -f app.log | grep -i error</code></td><td>새로 찍히는 에러만 흘려보냄 — 운영 디버깅 단골</td></tr>\n<tr><td>빠른 재귀 검색</td><td><code>rg -n \"timeout\" logs/</code></td><td>여러 로그 파일을 한 번에, 줄번호와 함께(→ 리눅스 핸드북 LX-04)</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">실시간 흐름 vs 탐색 — less +F</span>\n<span class=\"dim\"># 큰 로그를 열어 끝에서 실시간으로 따라가기</span><br>\nless <span class=\"seg2\">+F</span> app.log<br>\n<span class=\"dim\">#  Ctrl-C → 흐름 멈춤(탐색 모드)  /  /패턴 → 검색  /  Shift-F → 다시 실시간</span><br>\n<br>\n<span class=\"dim\"># 시간 범위로 좁히기 — 09:13~09:14 구간의 에러만</span><br>\ngrep <span class=\"seg2\">\"2026-06-23 09:1[34]\"</span> app.log <span class=\"dim\">|</span> grep -i error<br>\n<br>\n<span class=\"dim\"># docker 로그도 같은 방식 — 표준출력을 grep으로 받음</span><br>\ndocker logs <span class=\"seg\">api</span> <span class=\"seg2\">2&gt;&amp;1</span> <span class=\"dim\">|</span> grep -i error\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">함정 — 에러는 stderr로 나간다</span>\n<p><code>docker logs api | grep error</code>가 비어 나오면, 에러가 <em>stderr</em>로 나가는데 파이프는 기본적으로 stdout만 넘기기 때문일 수 있습니다. <code>docker logs api 2&gt;&amp;1 | grep error</code>로 stderr를 stdout에 합쳐서 받으세요(<code>2&gt;&amp;1</code>의 의미는 → 리눅스 핸드북 LX-08). <code>tail -f | grep</code>은 실시간이지만 <em>과거 로그를 거슬러 검색하진 못합니다</em> — 지나간 구간을 뒤지려면 <code>less +F</code>로 멈춰서 <code>/</code> 검색을 쓰세요.</p>\n</div>\n</section>\n\n<!-- ============ CH 3 ============ -->\n<section id=\"logs-ch3\">\n<div class=\"ch-head\"><span class=\"ch-code\">LOGTL-03</span><h2>구조화(JSON) 로그 조회</h2></div>\n<p class=\"lede\">로그가 JSON 한 줄(JSON Lines)이면 <code>grep</code>으로 문자열을 긁는 대신 <em>필드로</em> 묻습니다 — \"level이 ERROR이고 traceId가 X인 줄\". <code>jq</code>가 그 도구입니다. 상관관계 ID 하나로 한 요청의 전 구간을 꿰는 것이 핵심.</p>\n<table>\n<tr><th>목적</th><th>명령</th><th>왜</th></tr>\n<tr><td>필드만 추출</td><td><code>jq '.message' app.log</code></td><td>JSON 전체 대신 보고 싶은 필드만 — 눈이 덜 피로함</td></tr>\n<tr><td>레벨로 필터</td><td><code>jq 'select(.level==\"ERROR\")' app.log</code></td><td>구조화 필드로 정확히 거름 — 문자열 매칭의 오탐 없음</td></tr>\n<tr><td>여러 필드 조립</td><td><code>jq -r '[.ts,.level,.msg]|@tsv' app.log</code></td><td><code>-r</code>로 따옴표 없이, 탭 구분 표로 — 읽기 좋게</td></tr>\n<tr><td>요청 하나 추적</td><td><code>jq 'select(.traceId==\"abc123\")' app.log</code></td><td>상관관계 ID로 한 요청의 모든 로그를 모음</td></tr>\n<tr><td>docker 로그를 jq로</td><td><code>docker logs api | jq 'select(.level==\"ERROR\")'</code></td><td>컨테이너가 JSON으로 찍으면 바로 파이프</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">상관관계 ID로 한 요청을 꿰기</span>\n<span class=\"dim\"># 1) 에러 줄에서 traceId를 먼저 뽑는다</span><br>\njq <span class=\"seg2\">-r 'select(.level==\"ERROR\") | .traceId'</span> app.log<br>\n<br>\n<span class=\"dim\"># 2) 그 ID로 한 요청의 전 구간을 시간순으로 — 왜 이 흐름이 실패했나</span><br>\njq <span class=\"seg2\">-c 'select(.traceId==\"abc123\")'</span> app.log<br>\n<br>\n<span class=\"dim\"># 3) 여러 서비스 로그를 합쳐서 한 요청을 본다 (timestamp로 정렬)</span><br>\ncat api.log gateway.log <span class=\"dim\">|</span> jq <span class=\"seg2\">-c 'select(.traceId==\"abc123\")'</span> <span class=\"dim\">|</span> sort\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">왜 구조화 로그인가 → 관측가능성 핸드북</span>\n<p>문자열 로그는 사람이 읽기엔 편하지만 기계가 묻기엔 약합니다. 구조화 로그(JSON)는 필드로 질의·집계·알람이 가능해집니다 — <code>jq</code>로 로컬에서 묻는 것이 클라우드 로그 쿼리(CloudWatch Insights 등)의 사고 모델과 같습니다. <strong>traceId / spanId 같은 상관관계 ID를 모든 로그에 심는 것</strong>이 분산 추적의 출발점입니다(이 ID를 서비스 경계를 넘어 전파하는 방법, 로그·메트릭·트레이스의 관계는 관측가능성 핸드북 참고).</p>\n</div>\n</section>\n\n<!-- ============ CH 4 ============ -->\n<section id=\"logs-ch4\">\n<div class=\"ch-head\"><span class=\"ch-code\">LOGTL-04</span><h2>런타임 로그 레벨 변경</h2></div>\n<p class=\"lede\">DEBUG 로그를 보려고 재배포하는 건 느리고 위험합니다. Spring Boot는 <em>재시작 없이</em> 특정 패키지의 로그 레벨을 바꿀 수 있습니다 — Actuator의 <code>/loggers</code> 엔드포인트. 평소엔 INFO, 문제 추적할 때만 그 패키지를 DEBUG로 올렸다 내립니다.</p>\n<table>\n<tr><th>방법</th><th>형태</th><th>왜</th></tr>\n<tr><td>설정 파일(정적)</td><td><code>logging.level.com.greenery=DEBUG</code> in <code>application.yml</code></td><td>기본 레벨 — 재시작 시 적용. 영구 설정에 적합</td></tr>\n<tr><td>현재 레벨 조회</td><td><code>GET /actuator/loggers/com.greenery</code></td><td>지금 이 패키지가 무슨 레벨인지 확인부터</td></tr>\n<tr><td>런타임 변경</td><td><code>POST /actuator/loggers/com.greenery</code> + body</td><td><b>재시작 없이</b> 즉시 적용 — 운영 중 추적</td></tr>\n<tr><td>원복</td><td>body의 <code>configuredLevel</code>을 <code>null</code>로</td><td>임시 DEBUG는 끝나면 반드시 되돌림</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">재시작 없이 DEBUG로 — Actuator /loggers</span>\n<span class=\"dim\"># 1) application.yml — Actuator 엔드포인트 노출 (운영은 인증 뒤에)</span><br>\nmanagement.endpoints.web.exposure.include<span class=\"dim\">:</span> <span class=\"seg2\">loggers</span><br>\n<br>\n<span class=\"dim\"># 2) 현재 레벨 확인</span><br>\ncurl <span class=\"seg2\">-s</span> localhost:8080<span class=\"seg\">/actuator/loggers/com.greenery</span> <span class=\"dim\">|</span> jq<br>\n<br>\n<span class=\"dim\"># 3) 해당 패키지만 DEBUG로 — 즉시 적용, 재시작 불필요</span><br>\ncurl <span class=\"seg2\">-X POST</span> localhost:8080<span class=\"seg\">/actuator/loggers/com.greenery</span> <span class=\"dim\">\\</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">-H</span> <span class=\"dim\">\"Content-Type: application/json\"</span> <span class=\"seg2\">-d</span> <span class=\"dim\">'{\"configuredLevel\":\"DEBUG\"}'</span><br>\n<br>\n<span class=\"dim\"># 4) 추적 끝나면 원복 — null이면 기본 레벨로 돌아감</span><br>\ncurl <span class=\"seg2\">-X POST</span> localhost:8080<span class=\"seg\">/actuator/loggers/com.greenery</span> <span class=\"dim\">\\</span><br>\n&nbsp;&nbsp;<span class=\"seg2\">-H</span> <span class=\"dim\">\"Content-Type: application/json\"</span> <span class=\"seg2\">-d</span> <span class=\"dim\">'{\"configuredLevel\":null}'</span>\n</div>\n<div class=\"callout risk\">\n<span class=\"co-label\">운영에서 DEBUG는 양날의 검</span>\n<p>전체를 DEBUG로 올리면 로그가 폭증해 디스크·비용·성능을 때리고, 민감정보(요청 바디, 쿼리 파라미터)가 로그로 새어나올 수 있습니다. <strong>꼭 의심 가는 패키지만, 짧게, 끝나면 즉시 원복.</strong> Actuator 엔드포인트는 운영에서 반드시 인증·네트워크 제한 뒤에 둬야 합니다 — 노출되면 누구나 로그 레벨을 바꾸고 내부 정보를 봅니다. root 로거(<code>/actuator/loggers/ROOT</code>) 변경은 특히 신중히.</p>\n</div>\n</section>\n\n<!-- ============ CH 5 ============ -->\n<section id=\"logs-ch5\">\n<div class=\"ch-head\"><span class=\"ch-code\">LOGTL-05</span><h2>셸 alias·함수</h2></div>\n<p class=\"lede\">같은 긴 명령을 하루에 열 번 친다면 그건 <code>alias</code>나 <code>function</code>으로 만들 신호입니다. 인자 없이 고정이면 alias, 인자를 받아야 하면 function. 그리고 <code>~/.zshrc</code>는 chezmoi로 관리합니다 — 손으로 직접 고치지 마세요(→ 리눅스 핸드북 LX-13).</p>\n<table>\n<tr><th>형태</th><th>예시</th><th>왜</th></tr>\n<tr><td>alias(고정 명령)</td><td><code>alias dl='docker compose logs -f'</code></td><td>인자 없이 늘 같은 명령 — 가장 단순</td></tr>\n<tr><td>function(인자 받음)</td><td><code>dlog() { docker logs -f \"$1\"; }</code></td><td>컨테이너 이름이 매번 달라짐 — <code>$1</code>로 받음</td></tr>\n<tr><td>여러 단계 묶기</td><td>function 안에서 파이프·여러 명령</td><td>alias로는 못 하는 조합 로직을 function으로</td></tr>\n<tr><td>현재 셸에 로드</td><td><code>source ~/.zshrc</code></td><td>새 alias는 새 셸이나 source 후에 보임</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">~/.zshrc — 로그 작업용 alias·함수</span>\n<span class=\"dim\"># 자주 치는 명령은 alias로</span><br>\nalias <span class=\"seg\">dps</span>=<span class=\"dim\">'docker ps --format \"table {{.Names}}\\t{{.Status}}\"'</span><br>\nalias <span class=\"seg\">dcl</span>=<span class=\"dim\">'docker compose logs -f'</span><br>\n<br>\n<span class=\"dim\"># 인자가 필요하면 function — 컨테이너의 에러만 실시간으로</span><br>\n<span class=\"seg\">elog</span>() {<br>\n&nbsp;&nbsp;docker logs <span class=\"seg2\">-f</span> <span class=\"dim\">\"$1\"</span> <span class=\"seg2\">2&gt;&amp;1</span> <span class=\"dim\">|</span> grep <span class=\"seg2\">--line-buffered</span> -i error<br>\n}<br>\n<span class=\"dim\"># 사용:  elog api   ← $1 자리에 컨테이너 이름</span><br>\n<br>\n<span class=\"dim\"># 특정 traceId로 JSON 로그 추적</span><br>\n<span class=\"seg\">trace</span>() {<br>\n&nbsp;&nbsp;docker logs <span class=\"dim\">\"$1\"</span> <span class=\"seg2\">2&gt;&amp;1</span> <span class=\"dim\">|</span> jq <span class=\"seg2\">-c</span> <span class=\"dim\">\"select(.traceId==\\\"$2\\\")\"</span><br>\n}<br>\n<span class=\"dim\"># 사용:  trace api abc123</span>\n</div>\n<div class=\"callout warn\">\n<span class=\"co-label\">chezmoi로 관리 · grep 버퍼링</span>\n<p><code>~/.zshrc</code>를 직접 고치면 chezmoi 관리와 어긋납니다 — <code>chezmoi edit ~/.zshrc</code>로 고치고 <code>chezmoi apply</code>, 그다음 <code>source ~/.zshrc</code>로 현재 셸에 반영하세요. 그리고 <code>tail -f | grep</code>이 실시간인데 출력이 안 나오면 grep의 버퍼링 탓일 수 있습니다 — <code>grep --line-buffered</code>로 줄 단위로 흘려보내세요. function의 인자는 <code>\"$1\"</code>처럼 <em>반드시 따옴표로 감싸</em> 공백·특수문자에 깨지지 않게 합니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 6 ============ -->\n<section id=\"logs-ch6\">\n<div class=\"ch-head\"><span class=\"ch-code\">LOGTL-06</span><h2>스크립트화</h2></div>\n<p class=\"lede\">function이 한 줄로 안 끝나고 단계가 여럿이거나 팀과 공유해야 하면 <code>.sh</code> 파일로 만듭니다. 핵심은 세 가지 — shebang으로 인터프리터 명시, <code>set -euo pipefail</code>로 실패 시 멈춤, 위험한 작업엔 가드. 스크립트는 <em>조용히 실패하면 안 됩니다</em>.</p>\n<table>\n<tr><th>요소</th><th>형태</th><th>왜</th></tr>\n<tr><td>shebang</td><td><code>#!/usr/bin/env bash</code></td><td>어떤 인터프리터로 실행할지 명시 — 이식성</td></tr>\n<tr><td>안전 가드</td><td><code>set -euo pipefail</code></td><td>에러·미정의 변수·파이프 실패에서 즉시 중단 — 사고 전파 차단</td></tr>\n<tr><td>인자 받기</td><td><code>\"$1\"</code>, <code>\"$@\"</code>, <code>${1:?메시지}</code></td><td>인자 없으면 메시지 내고 종료(<code>:?</code>) — 빈 인자로 폭주 방지</td></tr>\n<tr><td>실행 권한</td><td><code>chmod +x reset-db.sh</code></td><td>실행 비트가 있어야 <code>./reset-db.sh</code>로 돌아감</td></tr>\n<tr><td>운영 거부 가드</td><td>환경변수 확인 후 운영이면 <code>exit 1</code></td><td>파괴적 스크립트가 운영에서 도는 사고를 코드로 막음</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">reset-db.sh — 가드를 갖춘 파괴적 스크립트</span>\n<span class=\"seg2\">#!/usr/bin/env bash</span><br>\n<span class=\"dim\"># 에러/미정의변수/파이프실패에서 즉시 멈춤 — 절반만 실행되는 사고 방지</span><br>\nset <span class=\"seg\">-euo pipefail</span><br>\n<br>\n<span class=\"dim\"># 운영에서는 절대 못 돌게 — 가장 먼저 거부 가드</span><br>\n<span class=\"seg2\">if</span> [[ <span class=\"dim\">\"${APP_ENV:-}\"</span> == <span class=\"dim\">\"production\"</span> ]]; <span class=\"seg2\">then</span><br>\n&nbsp;&nbsp;echo <span class=\"dim\">\"refusing to reset production DB\"</span> <span class=\"seg2\">&gt;&amp;2</span>; exit 1<br>\n<span class=\"seg2\">fi</span><br>\n<br>\n<span class=\"dim\"># 인자 필수 — 없으면 메시지 내고 종료</span><br>\nDB_NAME=<span class=\"dim\">\"${1:?usage: reset-db.sh &lt;dbname&gt;}\"</span><br>\n<br>\necho <span class=\"dim\">\"resetting ${DB_NAME} ...\"</span><br>\ndropdb <span class=\"seg2\">--if-exists</span> <span class=\"dim\">\"$DB_NAME\"</span><br>\ncreatedb <span class=\"dim\">\"$DB_NAME\"</span><br>\necho <span class=\"dim\">\"done.\"</span>\n</div>\n<div class=\"callout risk\">\n<span class=\"co-label\">파괴적 스크립트의 규칙 → 실무 플레이북</span>\n<p>DB를 지우거나 데이터를 옮기는 스크립트는 <strong>가드를 먼저, 작업을 나중에</strong> 짭니다 — <code>set -euo pipefail</code>은 기본이고, 운영 환경 거부 가드와 필수 인자 검증(<code>${1:?}</code>)을 맨 위에 둡니다. <code>set -e</code>가 있어도 파괴적 명령 전에 <code>echo</code>로 무엇을 할지 출력하고, 가능하면 확인 프롬프트(<code>read -p</code>)를 넣으세요. 운영 절차로 굳히는 법(승인·롤백·dry-run)은 실무 플레이북 참고.</p>\n</div>\n</section>\n\n<!-- ============ CH 7 ============ -->\n<section id=\"logs-ch7\">\n<div class=\"ch-head\"><span class=\"ch-code\">LOGTL-07</span><h2>프로젝트 커스텀 명령</h2></div>\n<p class=\"lede\">alias는 내 셸에만 있습니다. 팀이 공유해야 하는 명령은 <em>저장소 안에</em> 둡니다 — Gradle custom task, 또는 <code>Makefile</code>/<code>just</code>로 명령 모음을. 새 팀원이 <code>make up</code> 한 줄로 환경을 띄울 수 있게 하는 것이 목표입니다.</p>\n<table>\n<tr><th>방법</th><th>형태</th><th>왜</th></tr>\n<tr><td>Gradle custom task</td><td><code>./gradlew printLogs</code></td><td>빌드 도구 안에서 — JVM·의존성 컨텍스트가 필요한 작업에</td></tr>\n<tr><td>Makefile</td><td><code>make up</code>, <code>make logs</code></td><td>어디에나 있는 도구 — 언어 무관 명령 모음의 표준</td></tr>\n<tr><td>just</td><td><code>just logs api</code></td><td>Make의 함정(탭·암묵 규칙) 없는 모던 대체 — 인자 받기 깔끔</td></tr>\n<tr><td>팀 공유</td><td>이 파일들을 저장소에 커밋</td><td>명령이 코드와 함께 버전 관리됨 — 온보딩이 한 줄</td></tr>\n</table>\n<div class=\"serial-card\">\n<span class=\"sc-label\">Makefile — 팀 공용 명령 모음</span>\n<span class=\"dim\"># .PHONY: 같은 이름의 파일이 있어도 항상 명령으로 실행</span><br>\n.PHONY: up down logs<br>\n<br>\nup:<span class=\"seg2\">  ## 개발 스택 기동</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;docker compose up <span class=\"seg\">-d</span><br>\n<br>\nlogs:<span class=\"seg2\">  ## 서비스 로그 실시간 (예: make logs svc=api)</span><br>\n&nbsp;&nbsp;&nbsp;&nbsp;docker compose logs <span class=\"seg\">-f</span> <span class=\"dim\">$(svc)</span><br>\n<br>\n<span class=\"dim\"># 사용:  make up   /   make logs svc=api</span><br>\n<br>\n<span class=\"sc-label\">build.gradle(.kts) — 커스텀 task</span>\ntasks.register(<span class=\"dim\">\"printRoutes\"</span>) {<br>\n&nbsp;&nbsp;group = <span class=\"dim\">\"help\"</span><br>\n&nbsp;&nbsp;doLast { println(<span class=\"dim\">\"GET /api/credits ...\"</span>) }<br>\n}<br>\n<span class=\"dim\"># 사용:  ./gradlew printRoutes</span>\n</div>\n<div class=\"callout\">\n<span class=\"co-label\">선택 기준</span>\n<p>JVM 빌드 컨텍스트(클래스패스·Spring 설정)가 필요하면 Gradle task. 그냥 명령 묶음(docker·db·migration 호출)이면 <code>Makefile</code>이나 <code>just</code>가 가볍고 빠릅니다. Make는 <em>레시피 줄 들여쓰기가 반드시 탭</em>이어야 하는 함정이 있어, 인자를 자주 받는다면 <code>just</code>(<code>justfile</code>)가 더 편합니다. 어느 쪽이든 핵심은 <strong>저장소에 커밋해 팀이 공유</strong>하는 것 — alias는 개인용, 이건 팀용입니다.</p>\n</div>\n</section>\n\n<!-- ============ CH 8 ============ -->\n<section id=\"logs-ch8\">\n<div class=\"ch-head\"><span class=\"ch-code\">LOGTL-08</span><h2>치트시트 — 자주 쓰는 한 줄</h2></div>\n<p class=\"lede\">로그 추적과 명령 자동화에서 반복되는 조합들. 외우기보다 \"이런 게 가능하다\"를 알아두고 필요할 때 찾으세요.</p>\n<div class=\"glossary\">\n<div class=\"g-row\"><div class=\"g-term\"><b>컨테이너 로그 실시간</b><span>docker logs</span></div><div class=\"g-def\"><code>docker logs -f --tail 100 &lt;c&gt;</code> — 마지막 100줄부터 실시간 추적</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>compose 서비스 로그</b><span>compose logs</span></div><div class=\"g-def\"><code>docker compose logs -f -t &lt;svc&gt;</code> — 서비스만, 타임스탬프 포함</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>systemd 서비스 로그</b><span>journalctl</span></div><div class=\"g-def\"><code>journalctl -u &lt;svc&gt; -b -f</code> — 부팅 이후 + 실시간</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>에러만 추리기</b><span>grep / rg</span></div><div class=\"g-def\"><code>grep -i -C 3 error app.log</code> — 대소문자 무시, 전후 3줄 맥락</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>실시간 + 필터</b><span>tail -f | grep</span></div><div class=\"g-def\"><code>tail -f app.log | grep --line-buffered -i error</code> — 버퍼링 끄고 실시간</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>JSON 필드로 필터</b><span>jq select</span></div><div class=\"g-def\"><code>jq 'select(.level==\"ERROR\")' app.log</code> — 문자열 아닌 필드로 정확히</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>한 요청 추적</b><span>traceId</span></div><div class=\"g-def\"><code>jq -c 'select(.traceId==\"abc123\")' app.log</code> — 상관관계 ID로 전 구간</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>실시간 탐색</b><span>less +F</span></div><div class=\"g-def\"><code>less +F app.log</code> — Ctrl-C로 멈춰 <code>/</code> 검색, Shift-F로 다시 실시간</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>런타임 로그 레벨</b><span>actuator loggers</span></div><div class=\"g-def\"><code>curl -X POST .../actuator/loggers/&lt;pkg&gt; -d '{\"configuredLevel\":\"DEBUG\"}'</code> — 재시작 없이</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>인자 받는 함수</b><span>zsh function</span></div><div class=\"g-def\"><code>dlog() { docker logs -f \"$1\"; }</code> — <code>~/.zshrc</code>에, chezmoi로 관리</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>스크립트 안전 가드</b><span>set -euo pipefail</span></div><div class=\"g-def\">파일 맨 위에 <code>set -euo pipefail</code> + 운영 거부 가드 + <code>${1:?usage}</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>팀 공용 명령</b><span>Makefile / just</span></div><div class=\"g-def\"><code>make up</code> · <code>make logs svc=api</code> · <code>just logs api</code> — 저장소에 커밋</div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>Gradle 커스텀 task</b><span>gradle task</span></div><div class=\"g-def\"><code>tasks.register(\"printRoutes\") { ... }</code> → <code>./gradlew printRoutes</code></div></div>\n<div class=\"g-row\"><div class=\"g-term\"><b>stderr까지 잡기</b><span>2&gt;&amp;1</span></div><div class=\"g-def\"><code>docker logs api 2&gt;&amp;1 | grep error</code> — 에러가 stderr로 갈 때</div></div>\n</div>\n<div class=\"callout gm\">\n<span class=\"co-label\">함께 보기</span>\n<p>이 가이드는 <strong>리눅스 핸드북</strong>(grep·rg·tail·less·파이프·alias의 기초 — LX-04·LX-08·LX-13)과 <strong>관측가능성 핸드북</strong>(구조화 로그·분산 추적·상관관계 ID 전파)의 실무 접점입니다. 파괴적 스크립트를 운영 절차로 굳히는 법은 실무 플레이북을 보세요. 손에 먼저 붙일 것: <code>docker compose logs -f</code> · <code>tail -f | grep</code> · <code>jq select</code> · <code>traceId 추적</code> · <code>actuator/loggers</code> · 자주 치는 건 alias로. 나머지는 필요할 때 여기서 찾으면 됩니다.</p>\n</div>\n</section>\n\n<footer>\nLOGS &amp; TOOLING — 로그 조회·커스텀 명령 가이드 · V1 · 2026-06<br>\nENV : macOS(Darwin) · zsh · Docker · Spring Boot · Gradle · jq<br>\nCOMPANION : LINUX/SHELL HANDBOOK(LX-04·08·13) · OBSERVABILITY HANDBOOK · 실무 플레이북\n</footer>",
};

export default document;
